VALUES ('faq-close-workpapers', 'close-v1.1.0', 'close-08', 'Storage', 'Procedure', 'Where are close workpapers stored?', 'In the controlled close evidence repository linked from the execution record; email attachments are not the system of record.', 'https://w3id.org/pko#FrequentlyAskedQuestion') ON CONFLICT (faq_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, category = EXCLUDED.category, target_kind = EXCLUDED.target_kind, question = EXCLUDED.question, answer = EXCLUDED.answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

