VALUES ('faq-policy-ai', 'policy-v1.0.0', 'policy-03', 'Authority', 'Procedure', 'Can the drafting AI approve a workforce policy?', 'No. It may draft from approved sources, but a human policy owner and legal reviewer must approve the commitments.', 'https://w3id.org/pko#FrequentlyAskedQuestion') ON CONFLICT (faq_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, category = EXCLUDED.category, target_kind = EXCLUDED.target_kind, question = EXCLUDED.question, answer = EXCLUDED.answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

