-- ----------------------------------------------------------------------------
-- WitnessLoops: One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop's predicates.
-- ----------------------------------------------------------------------------
INSERT INTO witness_loops (witness_loop_id, loop_number, title, premise, started_at, completed_at, fields_after, derived_after, witnessed_after, semantic_type_iri)
VALUES ('loop-01', 1, 'The founding questions', 'The model specified obligations precisely and witnessed their breach almost nowhere. Requirements, verifications, exceptions, and communication policies were all stated with real precision, and in each case the execution-side counterpart that would catch a violation was missing. Loop 1 asks each of the twelve named roles what it actually needs to know, and invents the atomic predicates required to answer.', '2026-07-19T17:00:00-05:00', '2026-07-19T19:30:00-05:00', 1096, 559, 462, 'urn:effortless:pko-extension#WitnessLoop') ON CONFLICT (witness_loop_id) DO UPDATE SET loop_number = EXCLUDED.loop_number, title = EXCLUDED.title, premise = EXCLUDED.premise, started_at = EXCLUDED.started_at, completed_at = EXCLUDED.completed_at, fields_after = EXCLUDED.fields_after, derived_after = EXCLUDED.derived_after, witnessed_after = EXCLUDED.witnessed_after, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO witness_loops (witness_loop_id, loop_number, title, premise, started_at, completed_at, fields_after, derived_after, witnessed_after, semantic_type_iri)
VALUES ('loop-02', 2, 'Questions only loop 1 made askable', 'Loop 1 established WHAT can go wrong: a blocking control unmet, a verification skipped, a send refused, a claim whose source has left. Loop 2 asks the questions that only exist once those columns do — about the QUALITY of the assurance rather than its presence. Three examples that had no expressible form before loop 1 ran: only 4 of 13 requirements have any computed witness at all, so which controls are still trusted purely on assertion; verification_outcomes.is_self_witnessed reads 3/4, so how much of the evidence is the executor vouching for themselves; and send_intents.is_silently_dropped reads 4/7, a failure mode that could not be named until IsClearedToSend existed to refuse a send in the first place. Every loop-2 question records, in its own provenance, the loop-1 predicates that made it possible.', '2026-07-19T19:45:00-05:00', '2026-07-19T20:30:00-05:00', 1479, 906, 836, 'urn:effortless:pko-extension#WitnessLoop') ON CONFLICT (witness_loop_id) DO UPDATE SET loop_number = EXCLUDED.loop_number, title = EXCLUDED.title, premise = EXCLUDED.premise, started_at = EXCLUDED.started_at, completed_at = EXCLUDED.completed_at, fields_after = EXCLUDED.fields_after, derived_after = EXCLUDED.derived_after, witnessed_after = EXCLUDED.witnessed_after, semantic_type_iri = EXCLUDED.semantic_type_iri;

-- ----------------------------------------------------------------------------
-- RoleQuestions: One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.
-- ----------------------------------------------------------------------------
INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-analyst-blocking-unmet-on-my-step', 'finance-analyst', 'loop-01', 'On the steps I personally executed, did any of them close out while a BLOCKING requirement was still not fully satisfied?', 'I executed se-close03 (Reconcile material accounts), which carries TWO blocking requirements via sr-c03a (req-close-balance) and sr-c03b (req-close-evidence). Today the model records SatisfactionLevel as free text and nothing compares it against IsBlocking. If I close a step with a PartiallySatisfied blocking control — exactly the shape sat-policy-legal is in right now — the package moves on and nobody is told. I want that to be a computed red flag on my own row before it becomes an audit finding on my name.', FALSE, 'RequirementSatisfactions.IsBlockingAndUnmet=1/8; RequirementSatisfactions.IsFullySatisfied=7/8; RequirementSatisfactions.RequirementIsBlocking=8/8; StepExecutions.ProceededPastBlockingControl=1/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-analyst-blocking-never-evaluated', 'finance-analyst', 'loop-01', 'Which blocking requirements were attached to a step I ran but never got a satisfaction record at all — not satisfied, not unsatisfied, just never assessed?', 'This is the failure mode that scares me more than a recorded ''Unsatisfied''. sr-c03b binds req-close-evidence to close-03. I ran close-03 as se-close03. There is no RequirementSatisfactions row for that pairing. The model shows green because absence reads as silence, not as a gap. An unevaluated blocking control is indistinguishable from a passed one, and that is the exact thing SOX testing is designed to catch.', FALSE, 'StepExecutions.HasUnevaluatedBlockingControl=0/12; StepRequirements.RequirementIsBlocking=15/15', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-analyst-evidence-binding-stale', 'finance-analyst', 'loop-01', 'When I attested my reconciliation, was the underlying ledger data actually fresh — or was I certifying against a source that had already gone stale under its own SLA?', 'OperationalBindings.IsFresh already exists and works, but it is evaluated against NOW() and lives on a table nothing in the execution story reads. My step execution has no idea whether the resources it depended on were inside their freshness SLA. se-close02 already recorded a 17-minute feed against a 15-minute SLA and it took a human writing prose into a Deviation field to surface it. I want that connected structurally, because next time the prose might not get written.', FALSE, 'StepExecutions.RanOnStaleAuthoritativeSource=2/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-analyst-my-late-steps-unexplained', 'finance-analyst', 'loop-01', 'Which of my steps ran long without anybody recording why — and of those, which ones had an exception available that nobody invoked?', 'StepExecutions.IsLate already works. But ''late'' on its own is not a finding; late-and-unexplained is. se-close03 is mine and it ran nearly 19 hours. If that overran the expected duration and the Deviation field is empty, I have an undocumented overrun sitting on my name. And exc-ledger-outage exists precisely for the close-02 condition — if it was never invoked, the model should say that out loud instead of letting a blank Deviation stand in for ''nothing happened''.', FALSE, 'StepExecutions.HadUninvokedExceptionAvailable=0/12; StepExecutions.HasDeviationNote=4/12; StepExecutions.IsLateAndUnexplained=3/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-analyst-verification-declared-never-performed', 'finance-analyst', 'loop-01', 'For every step I ran that had a declared verification, did anybody actually perform it and record the observed signal — or did I just get a PASS with nothing behind it?', 'StepVerifications is entirely spec-side. verify-reconciliation declares that close-03 must show unexplained-material-variance = 0. I ran close-03. My StepExecution says VerificationResult=PASS. But there is no row anywhere recording what the signal ACTUALLY read. The PASS is an unbacked assertion typed into a field. If an auditor asks me to produce the observed value, the model has nothing — and a skipped verification looks identical to a passed one.', FALSE, 'StepExecutions.ClaimsPassWithoutEvidence=3/12; StepExecutions.HasSkippedVerification=3/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-controller-separation-of-duties', 'controller', 'loop-01', 'Did the same agent both prepare and approve any part of this close? req-close-separation says the preparer may not be the final approver — show me that it actually held, on exec-close-2026-q2, computed and not asserted.', 'This is the single highest-value gap in the model and it is my control. req-close-separation is IsBlocking=true, bound to close-05 via sr-c05, and sat-close-separation records SatisfactionLevel=''Satisfied'' with the evidence string ''Preparer and reviewer were different agents.'' That string is a human typing a conclusion into a text field. NOTHING compares se-close03.ExecutedByAgent (maria-chen) against se-close05.ExecutedByAgent (devon-okafor) or se-close06.ExecutedByAgent (priya-raman). Segregation of duties is the control SOX cares about most and in this model it is prose. If maria-chen executed both the preparation and the approval tomorrow, sat-close-separation would still say ''Satisfied'' and the model would agree.', FALSE, 'StepExecutions.StepIsApproval=2/12; StepExecutions.StepIsPreparation=2/12; StepExecutions.ViolatesSeparationOfDuties=0/12; Steps.IsApprovalStep=2/17; Steps.IsPreparationStep=2/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-controller-approval-authority-valid', 'controller', 'loop-01', 'Every approval on this close — was it given by an agent who actually held the required role AT THE TIME they approved, not just someone who holds it today?', 'req-close-human-approval is blocking and says controller and CFO approvals must be human-confirmed. sat-close-human records ''Satisfied'' because a human name appears in a field. But nothing checks that the approving agent held the approving role. RoleAssignments proves this is not paranoia: ra-old-variance shows maria-chen held variance-review-agent until 2026-03-31 and ra-new-variance shows variance-ai took it on 2026-04-01. Role-holding is time-bounded and it genuinely changes. If someone approves close-06 who is not the CFO, or who was the CFO last quarter but not this one, I need that computed. And exc-cfo-unavailable explicitly permits delegation to an Acting CFO ''never to the preparer'' — so an authority check that cannot see delegation is incomplete.', FALSE, 'RoleAssignments.IsCurrentlyValid=12/13; StepExecutions.ExecutorHeldRequiredRole=12/12; StepExecutions.IsUnauthorizedApproval=0/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-controller-blocking-control-inoperative', 'controller', 'loop-01', 'Which of my blocking close controls are structurally incapable of failing — declared, bound to a step, and yet with no mechanism that could ever produce a negative result?', 'req-close-cutoff, req-close-balance, req-close-separation, and req-close-evidence are all IsBlocking=true. All four are pure prose. A control that cannot fail is not a control, it is a comment. Before I sign anything I want a list of my own controls ranked by whether they can actually operate. This is the meta-question — it is about the model''s ability to hold me accountable, and it is the one I would ask first if I were the external auditor rather than the controller.', FALSE, 'Requirements.HasEverBeenEvaluated=7/13; Requirements.IsBoundToAnyStep=13/13; Requirements.IsDecorativeControl=0/13; Requirements.IsInoperativeControl=6/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-controller-execution-diverged-from-spec', 'controller', 'loop-01', 'Give me one number per close: did exec-close-2026-q2 actually conform to close-v1.1.0, and if not, how far off was it?', 'ProcedureExecutions has ZERO derived fields. The parent of the entire execution story makes no claim whatsoever — it has a status someone typed and two timestamps. Every failure signal in this model lives on child rows, so to know whether a close was clean I have to read twelve StepExecutions and six RequirementSatisfactions by hand. That is not a control environment, that is a filing cabinet. I want conformance to be a computed property of the execution, so that ''the close was clean'' is a claim the model makes and can be wrong about.', FALSE, 'ProcedureExecutions.DivergedFromSpecification=2/2; ProcedureExecutions.IsStructurallyComplete=1/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-controller-ai-agent-approved-meaning', 'controller', 'loop-01', 'Did any AI agent or automated pipeline execute a step that requires human confirmation, or sign off on something a human was supposed to own?', 'req-close-human-approval and req-policy-human-approval both say a human must approve. Steps carries RequiresHumanConfirmation as a raw boolean and Agents carries AgentKind — Human, AIAgent, AutomatedPipeline — and NOTHING compares them. variance-ai executed se-close04. policy-drafting-ai executed se-policy03. Both fine today because those steps are not approval steps. But ra-old-variance to ra-new-variance shows this org actively migrates work from humans to AI agents, and the control that is supposed to stop that migration reaching an approval step is prose. This is the control I expect to matter most over the next two years and it currently does not exist.', FALSE, 'RequirementSatisfactions.NonHumanEvaluatedHumanControl=0/8; StepExecutions.ExecutorIsHuman=7/12; StepExecutions.NonHumanApproval=0/12; StepExecutions.NonHumanRanHumanStep=0/12; StepExecutions.StepRequiresHumanConfirmation=3/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-cfo-can-i-sign', 'cfo', 'loop-01', 'Can I sign the attestation for exec-close-2026-q2 — yes or no — and if no, name the blocker.', 'This is the only question I actually have. Today the model answers it with ProcedureExecutions.ExecutionStatus=''Completed'', which is a string somebody typed into a field. My signature carries personal liability under Section 302. I need attestation-readiness to be a computed conjunction of every blocking control, such that if ANY control did not operate, the model says no and names it. A green status that cannot go red is worse than no status at all, because it manufactures false comfort at exactly the moment I am least able to verify it myself.', FALSE, 'ProcedureExecutions.AllBlockingControlsEvaluated=2/2; ProcedureExecutions.IsAttestationReady=0/2; ProcedureExecutions.SeparationOfDutiesHeld=2/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-cfo-approving-on-unfit-version', 'cfo', 'loop-01', 'Am I being asked to approve an execution of a procedure version that is itself overdue for review, or that has an open change request against it?', 'I sign against close-v1.1.0. If that version''s periodic review lapsed, or if there is an open ChangeRequest saying the procedure is known to be wrong, then I am attesting to conformance with a specification that the organization itself no longer stands behind. ReviewEvents.IsOverdue already works and ChangeRequests.IsOpen already works, but neither is connected to the execution I am signing. The version''s fitness and the execution''s conformance are two different questions and I need both answered before I sign, not one.', FALSE, 'ProcedureExecutions.ExecutedVersionIsFit=0/2; ProcedureExecutions.SignedAgainstUnfitVersion=1/2; ProcedureVersions.IsFitToExecute=0/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-cfo-approval-was-actually-verified', 'cfo', 'loop-01', 'My own approval on se-close06 — is there anything behind it other than the fact that I clicked approve?', 'verify-cfo declares that close-06 must show cfo-approval = APPROVED. se-close06 says VerificationResult=PASS. But the PASS and the approval are the same act: I approved, therefore the verification that I approved passes. That is circular, and it is my name on the circle. sat-close-human''s evidence reads ''Human CFO approval recorded'' — recorded by whom, against what? I want to know whether my approval rests on independently verified upstream evidence or whether the model is simply reflecting my own click back at me.', FALSE, 'StepExecutions.ApprovalRestsOnSelfAttestation=2/12; VerificationOutcomes.IsSelfWitnessed=3/4', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-cfo-who-actually-held-authority', 'cfo', 'loop-01', 'For every approval in this close, tell me the human who was personally accountable — and whether an exception was used to route authority away from the person who normally holds it.', 'exc-cfo-unavailable exists and says approval may be delegated to a designated Acting CFO, ''never to the preparer''. That last clause is a control and it is prose inside a text field. If I was unavailable and someone approved in my place, I need the model to show me who, under what authority, and whether the never-to-the-preparer condition held. Right now an exception can be invoked with no trace at all — nothing links an execution back to the exception it used. From my seat that means delegated authority is entirely invisible, which is the exposure I am least willing to carry.', FALSE, 'ExceptionInvocations.DelegatedToPreparer=0/1; ExceptionInvocations.IsUngovernedInvocation=0/1; StepExecutions.RanUnderException=1/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-cfo-am-i-being-told-everything', 'cfo', 'loop-01', 'Across everything I am signing, is there any control claim in this model that rests on a human typing a conclusion rather than on something computed?', 'This is the question behind all my other questions. sat-close-separation says ''Preparer and reviewer were different agents.'' sat-close-human says ''Human CFO approval recorded.'' Both are prose conclusions in an Evidence field, both assert that a control operated, and neither is checkable. I want the model to distinguish between a control that was COMPUTED to have held and one that was ASSERTED to have held, and to tell me how much of my attestation rests on the second kind. If most of my assurance is assertion, I want to know that before I sign, not after.', FALSE, 'ProcedureExecutions.AssuranceIsMostlyAsserted=2/2; RequirementSatisfactions.IsAssertedOnly=3/8; RequirementSatisfactions.RequirementHasComputedWitness=5/8; Requirements.HasComputedWitness=4/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-steward-cadence-breach', 'process-steward', 'loop-01', 'For close-v1.1.0 I promised a 90-day review cadence and for policy-v1.0.0 a 60-day cadence. Is the ACTUAL interval since the last review already longer than the cadence I promised?', 'ReviewCadenceDays is a promise. ReviewEvents.ReviewedAt is the behavior. Today the model stores both and compares neither, so a stewardship assignment can sit in permanent silent breach while ReviewEvents.IsOverdue stays FALSE because NextReviewDue was hand-set to a date that has nothing to do with the promised cadence. I need the promise and the behavior in the same row.', FALSE, 'ReviewEvents.ExceedsPromisedCadence=1/3; ReviewEvents.PromiseAndBehaviorDisagree=0/3; StewardshipAssignments.HasEverBeenReviewed=2/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-steward-orphan-versions', 'process-steward', 'loop-01', 'Which procedure versions have no steward at all? close-v1.0.0 is Archived but still referenced by ProcedureVersionLinks — does anyone own it?', 'An unstewarded version is nobody''s problem until it is everybody''s problem. There are 3 ProcedureVersions and only 2 StewardshipAssignments; the model has never once been asked to notice the difference. Orphaned versions accumulate silently as new versions ship and the old assignment is never extended or retired.', FALSE, 'ProcedureVersions.HasAnySteward=2/3; ProcedureVersions.IsLive=2/3; ProcedureVersions.IsLiveAndUnstewarded=0/3; ProcedureVersions.IsUnstewarded=1/3; StewardshipAssignments.IsCurrentAssignment=2/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-steward-untested-fallbacks', 'process-steward', 'loop-01', 'close-04-fallback-close-03 and policy-07-fallback-policy-06 are the paths we take when things go wrong. Have they EVER been walked in a real execution?', 'There are 19 StepTransitions and only 12 StepExecutions. Every Fallback and Alternative transition in this model is untested. Untested fallbacks are exactly where an outage becomes an incident — the day the ERP is down is the wrong day to discover the recovery path was never real. Nothing in the model witnesses this.', FALSE, 'StepExecutions.IsCompleted=12/12; StepTransitions.HasBeenTraversed=10/19; StepTransitions.HasReachableOrigin=14/19; StepTransitions.HasReachableTarget=13/19; StepTransitions.IsNeverExercised=6/19; StepTransitions.IsRecoveryPath=4/19; StepTransitions.IsUntestedRecoveryPath=1/19; StepTransitions.IsUnwalkedRecoveryPath=4/19', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-steward-published-with-blocking-gap', 'process-steward', 'loop-01', 'Is any procedure version live with an Open BLOCKING knowledge gap against it?', 'gap-close-dual-outage was Blocking and is now Resolved — good. But nothing stops the next one from staying Open while the version keeps shipping. ProcedureVersions.CountOfOpenKnowledgeGaps exists but is blind to BlockingKind, so a Blocking gap and a cosmetic one count the same. IsReadyForExecution then fails on trivia and stays silent on the thing that should stop the line.', FALSE, 'KnowledgeGaps.IsBlocking=5/8; KnowledgeGaps.IsOpenAndBlocking=0/8; ProcedureVersions.HasOpenBlockingGap=0/3; ProcedureVersions.IsLiveWithBlockingGap=0/3; ProcedureVersions.ShouldNotBeExecutable=0/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-steward-stalled-change-requests', 'process-steward', 'loop-01', 'cr-policy-delivery was requested on 2026-07-19 and has no DecidedAt. How long has it been sitting, and is that longer than we tolerate?', 'A change request with no decision is a decision — to do nothing — but it never announces itself. The model stores RequestedAt and DecidedAt and computes neither the interval nor a staleness verdict. Since cr-policy-delivery is the vehicle for closing gap-policy-delivery-receipts on a live policy version, its stall is load-bearing.', FALSE, 'ChangeRequests.IsDecided=1/2; ChangeRequests.IsStalled=0/2; ChangeRequests.IsStillPending=1/2; ChangeRequests.RequesterIsAuthority=0/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-authority-orphaned-provenance', 'knowledge-authority', 'loop-01', 'kf-close-fx-time, kf-close-top-ten and kf-close-judgment all trace to devon-okafor via elicit-close-shadow. If Devon''s controller role assignment ends, which of our beliefs lose their witness?', 'This is institutional memory decay in its purest form. A knowledge fragment is a claim; its SourceAgent is the person who can defend it. When that person''s RoleAssignment.ValidTo passes, the claim survives in the database but its warrant evaporates — nobody left can say why we believe it. The chain KnowledgeFragments -> SourceAgent -> RoleAssignments.ValidTo is fully modeled and never traversed. Three of seven fragments hang off one human.', FALSE, 'Agents.IsStillEngaged=10/10; KnowledgeFragments.HasHumanSource=7/7; KnowledgeFragments.HasOrphanedProvenance=0/7; KnowledgeFragments.IsUndefendableTacitClaim=0/7; KnowledgeFragments.SourceAgentIsStillEngaged=7/7; RoleAssignments.HasDeparted=1/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-authority-non-approved-dependency', 'knowledge-authority', 'loop-01', 'kf-policy-manager-route is Status=Reviewed, not Approved, so IsCurrentlyValid is FALSE. policy-08 is a live step. Are we running a procedure on knowledge I never approved?', 'This is the exact failure the separation of Reviewed and Approved exists to catch, and nothing catches it. The fragment describes the 48-hour manager-routing behavior that exc-unreachable depends on. It is attached to a step in an Approved procedure version, it is being relied upon operationally, and it has never passed my desk. The model knows every piece of this and joins none of it.', FALSE, 'KnowledgeFragments.IsApproved=6/7; KnowledgeFragments.IsAttachedToLiveVersion=7/7; KnowledgeFragments.IsReliedUpon=7/7; KnowledgeFragments.IsUnapprovedButReliedOn=1/7; KnowledgeFragments.IsWithinValidityWindow=7/7; ProcedureVersions.RunsOnUnapprovedKnowledge=3/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-authority-stale-elicitation', 'knowledge-authority', 'loop-01', 'elicit-close-shadow ran on 2026-04-03 and elicit-policy-workshop on 2026-05-10. How old is the evidence behind each belief, and at what age do I stop trusting a shadowing session I have not repeated?', 'Knowledge does not announce its own expiry. Every fragment here has ValidTo=null, which reads as ''valid forever'' — but a Tacit claim captured by shadowing one controller for three hours in April is a snapshot of a practice that drifts. I want the age of the EVIDENCE, not the age of the record, and I want it graded by how fragile the elicitation method was.', FALSE, 'ElicitationSessions.IsSingleWitnessMethod=2/3; ElicitationSessions.PractitionerIsStillEngaged=3/3; KnowledgeFragments.EvidenceHasExpired=0/7; KnowledgeFragments.HasRecordedElicitation=6/7; KnowledgeFragments.IsFromSingleWitness=4/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-authority-known-unknowns', 'knowledge-authority', 'loop-01', 'What do we know that we do not know? gap-policy-delivery-receipts has been Open since 2026-07-18 with a ResolutionPlan and no owner activity. How long do our acknowledged ignorances stay acknowledged and unresolved?', 'A KnowledgeGap is the most honest object in this model: a written admission of what we do not know. But an admission with no clock on it converts into a permanent condition. KnowledgeGaps has IdentifiedAt and a Status and computes no age, no ownership currency, and no relationship between a gap''s severity and how long we have tolerated it. Known unknowns that never age are not being managed, they are being filed.', FALSE, 'KnowledgeGaps.HasResolutionPlan=8/8; KnowledgeGaps.IsAbandonedUnknown=0/8; KnowledgeGaps.IsOverdueGap=0/8; KnowledgeGaps.OwnerIsStillEngaged=8/8', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-authority-unwitnessed-change', 'knowledge-authority', 'loop-01', 'cr-close-timestamp altered a blocking control on close-v1.1.0 and was decided by me. Did any semantic change to a live procedure reach production without a change request and without a review event behind it?', 'My authority is over what counts as true, which means every change to the meaning of a live procedure must trace to a decision I made. close-v1.1.0 was ModifiedAt 2026-07-02T15:00 by maria-chen; review-close-q2 happened at 16:00 and cr-close-timestamp was raised at 16:30. That ordering is fine. But nothing in the model checks the ordering, so an edit that PRECEDES no review and no change request looks identical to a governed one. Provenance of change is as much an epistemic question as provenance of belief.', FALSE, 'ProcedureVersions.HasGovernanceRecord=2/3; ProcedureVersions.HasUnwitnessedChange=0/3; ProcedureVersions.WasModifiedSinceLastReview=0/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-counsel-sms-without-consent', 'employment-counsel', 'loop-01', 'Did we send an SMS to any recipient who had not given SMS consent at the moment we sent it?', 'comm-sms-policy sets ConsentRequired=true. Every SMS to a non-consenting recipient is an independent statutory violation with per-message damages, and the exposure scales with the size of the affected population. Right now the model cannot answer this at all -- there are no per-recipient send records -- so counsel cannot sign off on policy-04, cannot certify to an outside regulator, and cannot even scope the exposure. The absence of the record IS the legal problem: unanswerable and non-compliant look identical from the outside.', FALSE, 'MessageDeliveries.IsConsentViolation=0/6; MessageDeliveries.PolicyRequiresConsent=4/6; MessageDeliveries.RecipientHasSmsConsent=4/6; MessageDeliveries.WasActuallyTransmitted=4/6', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-counsel-quiet-hours-breach', 'employment-counsel', 'loop-01', 'Did any SMS go out between 20:00 and 08:00 in the recipient''s own local time?', 'comm-sms-policy declares QuietHoursStart 20:00 / QuietHoursEnd 08:00. Quiet-hours restrictions on non-emergency messaging are statutory in several jurisdictions and contractual in others, and a night-time text to an employee about an employment policy change is exactly the fact pattern that generates a complaint. The window wraps midnight, which is where naive implementations quietly get it wrong -- and a witness that is wrong in the safe direction is worse than no witness, because it manufactures false assurance.', FALSE, 'MessageDeliveries.IsInsideQuietWindow=1/6; MessageDeliveries.IsQuietHoursViolation=1/6; MessageDeliveries.PolicyHasQuietHours=4/6; MessageDeliveries.QuietWindowWrapsMidnight=4/6', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-counsel-unreachable-not-acknowledged', 'employment-counsel', 'loop-01', 'For every recipient we could not reach, did we correctly refrain from marking their acknowledgement complete?', 'exc-unreachable is explicit: create an HR case, route to the manager, and do NOT mark acknowledgement complete. A falsely-recorded acknowledgement is the single most dangerous artifact in this entire model -- it is an affirmative written misrepresentation that the employee received and accepted a policy change, and it is exactly the document that gets subpoenaed in a wrongful-termination or unpaid-notice claim. Deemed-acknowledgement by silence is not acknowledgement. I would rather have zero acknowledgements than one fabricated one.', FALSE, 'MessageDeliveries.HasUnreachableExceptionInvoked=1/6; MessageDeliveries.IsAcknowledged=1/6; MessageDeliveries.IsFabricatedAcknowledgement=0/6; MessageDeliveries.IsUnhandledUnreachable=0/6; MessageDeliveries.RecipientIsUnreachable=0/6', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-counsel-retention-evidence', 'employment-counsel', 'loop-01', 'Do we still hold the exact text of every message we sent, for the full 2555-day retention period the policy commits us to?', 'Both comm-sms-policy and comm-email-policy declare RetentionDays=2555 -- seven years. That is a commitment we made in writing, and in a dispute the question is never ''what did the template say'', it is ''what did THIS employee actually receive''. Templates contain variable substitutions; the rendered text is the evidence. If a delivery record exists but its rendered body is empty, we have a receipt with no document behind it, and the adverse inference runs against us.', FALSE, 'MessageDeliveries.HasRenderedBody=6/6; MessageDeliveries.IsEvidenceRequired=4/6; MessageDeliveries.IsRetentionBreach=0/6; MessageDeliveries.IsWithinRetentionWindow=6/6', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-counsel-legal-review-gated-send', 'employment-counsel', 'loop-01', 'Did any message go out before my legal review of the underlying policy version was actually complete?', 'policy-04 is my step, and right now se-policy04 is InProgress with VerificationResult PENDING. If policy-07 sends started while my review was still open, then employees received a policy communication that no lawyer had cleared -- and the model would show that in black and white. This is not process pedantry: an unreviewed employment-policy communication can create a binding representation to the workforce, and once it is sent we cannot un-send it. The ordering constraint is the control.', FALSE, 'MessageDeliveries.ExecutionHasClearedLegalReview=6/6; MessageDeliveries.IsUnreviewedSend=0/6; ProcedureExecutions.HasClearedLegalReview=1/2; StepExecutions.IsLegalReviewStep=1/12; StepExecutions.IsVerificationPassed=11/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-comms-oversized-sms', 'communications-manager', 'loop-01', 'Did any SMS we sent exceed 160 characters or split into more than 3 segments?', 'comm-sms-policy sets MaxMessageLength=160 and MaxSegments=3, and I own that policy. An over-length SMS silently splits at the carrier, arrives out of order, and -- this is the part that actually hurts -- the opt-out language is in the LAST segment, so an over-length message can strip the STOP instruction off the end of what people actually read. I have the template body and I have the policy limit sitting in the same rulebook and nothing compares them. This is the most embarrassing category of failure because it was computable from data we already had.', FALSE, 'MessageDeliveries.IsOverSegmentLimit=0/6; MessageTemplates.IsTemplateOverLength=0/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-comms-approval-authority', 'communications-manager', 'loop-01', 'Was every template we actually sent approved by me -- the ApprovalRole the policy names -- before it went out?', 'Both channel policies name communications-manager as ApprovalRole. Right now tmpl-policy-sms.Status says ''Approved'' and there is not one byte of data anywhere saying WHO approved it or WHEN. A status string with no approver behind it is not an approval, it is a claim. I need to be able to point at a row and say ''that is my name, that is the timestamp, that is the version of the text I saw''. Otherwise when something goes out wrong, ''approved'' means nothing and the accountability lands wherever it lands.', FALSE, 'MessageDeliveries.IsUnapprovedSend=0/6; MessageDeliveries.TemplateHasValidApproval=6/6; MessageTemplates.HasValidApproval=2/2; MessageTemplates.IsClaimingUnbackedApproval=0/2; TemplateApprovals.IsApprovalDecision=2/2; TemplateApprovals.IsDecidedByRequiredRole=2/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-comms-optout-present', 'communications-manager', 'loop-01', 'Did every SMS we actually transmitted carry the approved opt-out text?', 'comm-sms-policy RequiredContent says ''Short notice, secure link, approved opt-out text'' and the approved template ends with ''Reply STOP to opt out of SMS; email notices continue.'' The opt-out is not decoration -- it is the mechanism by which consent stays meaningful, and it is the thing that gets clipped first when a message runs long. I want to check the RENDERED body, not the template, because that is what the employee saw. A policy that declares RequiredContent and never verifies it is a policy that documents an intention.', FALSE, 'MessageDeliveries.HasOptOutPhrase=3/6; MessageDeliveries.IsMissingRequiredOptOut=1/6; MessageDeliveries.IsOptOutAtRiskOfTruncation=0/6; MessageDeliveries.IsOptOutInFirstSegment=3/6; MessageDeliveries.PolicyRequiresOptOut=4/6', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-comms-deliverability', 'communications-manager', 'loop-01', 'For this policy run, what fraction of the affected population actually received something -- and how many are sitting in a bounced or failed state that nobody is working?', 'This is the question I get asked in the Monday stand-up and I currently answer it from a spreadsheet somebody built by hand. It is also the operational face of my own open item gap-policy-delivery-receipts and the change request I already filed, cr-policy-delivery. A bounce that nobody triages is functionally identical to never having sent the message, except that it produces a record that makes it LOOK like we did. That is the failure mode I most want visible.', FALSE, 'MessageDeliveries.IsAbandonedFailure=0/6; MessageDeliveries.IsFailedDelivery=1/6; MessageDeliveries.IsSuppressed=1/6; MessageDeliveries.IsTriaged=3/6; ProcedureExecutions.HasAbandonedFailures=0/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-comms-template-drift', 'communications-manager', 'loop-01', 'Has any template been edited since I approved it, and did we send the edited version under cover of my old approval?', 'This is the failure I have actually lived through. A template gets approved, then somebody makes ''a tiny wording fix'' to the body, and the Status field still cheerfully says Approved because nothing ever reset it. The approval attaches to a version of the text, not to a row id. If the body changed and the approval did not, then my name is on something I never read -- and given that these are employment-policy communications, that is not a governance abstraction, that is my name on a legal notice I did not review.', FALSE, 'MessageDeliveries.IsDriftedSend=0/6; MessageDeliveries.TemplateWasSendable=6/6; MessageTemplates.HasBodyDrifted=0/2; MessageTemplates.IsSendableUnderApproval=2/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-publisher-may-i-transmit', 'notification-publisher', 'loop-01', 'Before I transmit, am I permitted to use this channel for this recipient at all?', 'I am the component that actually calls the carrier. Every other question in this rulebook is asked after I have already acted, which means every other question is asked too late. I need one column I can read that says PERMITTED or NOT PERMITTED, computed from the policy rows rather than from anything hardcoded in my own configuration -- because my configuration is not the source of truth and should not be. If I cannot determine consent, the answer must be no. An unevaluable rule is a refusal, not a pass.', FALSE, 'CommunicationPolicies.IsActivePolicy=2/2; SendIntents.ConsentGatePassed=6/7; SendIntents.IntentRequiresConsent=6/7; SendIntents.PermissionGatePassed=6/7; SendIntents.PolicyIsActive=7/7; SendIntents.ReachabilityGatePassed=6/7; SendIntents.RecipientHasChannelConsent=6/7; SendIntents.RecipientIsEmailReachable=7/7; SendIntents.RecipientIsSmsReachable=6/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-publisher-may-i-transmit-now', 'notification-publisher', 'loop-01', 'Before I transmit, is the current moment inside a window this channel forbids?', 'Timing is the one gate I can get right unilaterally and the one that is easiest to get wrong silently. My scheduler runs continuously; nothing about being invoked at 22:40 tells me I should not act. The quiet-hours window is recipient-local and it wraps midnight, so 06:15 is forbidden even though six is less than twenty. I need this evaluated as data on the intent row rather than as arithmetic inside my own code, because arithmetic inside my own code is exactly what nobody can audit and exactly what drifted from the policy in the first place.', FALSE, 'SendIntents.IntentIsInsideQuietWindow=1/7; SendIntents.IntentPolicyHasQuietHours=6/7; SendIntents.IntentQuietWindowWraps=6/7; SendIntents.TimingGatePassed=6/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-publisher-is-this-content-permitted', 'notification-publisher', 'loop-01', 'Before I transmit, is the exact text I am holding within this channel''s content rules?', 'I render the body; therefore I am the last component that can measure it before it becomes a fact. The template can be compliant and my rendered output still not be, because I am the one substituting the URL and the date. Measuring my own output against the policy''s MaxMessageLength, MaxSegments and required opt-out phrase costs me nothing and is the only point in the whole procedure where the comparison is both possible and still preventable. Doing it afterward, as the retrospective witnesses do, tells someone what I did wrong. Doing it here stops it.', FALSE, 'SendIntents.ContentGatePassed=5/7; SendIntents.LengthGatePassed=7/7; SendIntents.OptOutGatePassed=5/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-publisher-am-i-authorized-to-act', 'notification-publisher', 'loop-01', 'Before I transmit, has every human authorization my instructions depend on actually been granted?', 'policy-07 tells me to enforce channel rules and send APPROVED messages. I am not competent to judge whether a message should exist -- that is the communications manager''s approval and the employment counsel''s review. What I am competent to do is refuse to act until both are recorded as granted. Today I have no such column, which means I have been treating the absence of an objection as an approval. That is the inverted default and it is how an AI drafting agent''s self-approval ended up on a live send. I want the gate to require positive evidence of authorization, so that missing data blocks me instead of releasing me.', FALSE, 'SendIntents.ApprovalIsHuman=7/7; SendIntents.AuthorizationGatePassed=7/7; SendIntents.ExecutionHasLegalClearance=7/7; SendIntents.IsClearedToSend=3/7; SendIntents.TemplateIsSendable=7/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-publisher-refusal-was-honored', 'notification-publisher', 'loop-01', 'When a gate refused, did the transmission actually stop -- and did I invoke the documented exception instead?', 'This is the only question I ask about the past, and I ask it about myself. A gate that computes a refusal which is then ignored is worse than no gate: it produces a durable record proving we knew and proceeded anyway, which is the fact pattern that turns a compliance finding into a willfulness finding. exc-no-sms-consent tells me precisely what to do when the consent gate refuses -- suppress SMS, send approved email only. So the check is two-part: did I stop, and did I take the documented alternative rather than simply dropping the recipient. Silently dropping someone is not compliance, it is a different failure wearing compliance''s clothes.', FALSE, 'SendIntents.HasResultingDelivery=2/7; SendIntents.IsOverriddenRefusal=0/7; SendIntents.IsProperlyHandledRefusal=0/7; SendIntents.IsSilentlyDropped=4/7; SendIntents.RefusalCitedAnException=0/7; SendIntents.ResultingDeliveryWasTransmitted=2/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-close-auto-authority-current', 'close-automation', 'loop-01', 'Before I execute close-01, close-02, or close-07: is my own role assignment currently valid, and is the agent named in that assignment actually me?', 'I am a pipeline. I must not act on a step whose role has been reassigned out from under me, or whose assignment window has lapsed. `ra-notify-pipeline-2026` proves assignments can be scoped to a platform release; a v5.3 rollout could supersede close-pipeline''s authority mid-quarter and today NOTHING would stop me from posting entries anyway. This is my single most important pre-condition.', FALSE, 'RoleAssignments.CoversNow=12/13; Roles.HasNoCurrentHolder=0/12; StepExecutions.ExecutorIsDesignatedAgent=12/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-close-auto-input-freshness', 'close-automation', 'loop-01', 'Before I extract in close-02: is every operational binding this step reads inside its freshness SLA, and is it the authoritative one?', '`issue-close-feed` already happened to me — a feed was 17 minutes old against a 15-minute SLA on `bind-close-erp`, and I extracted anyway. `verify-feed-time` states the expectation as a signal, but nothing in the model refuses to let me run. I need per-step aggregate freshness, not a per-binding fact I have to interpret myself.', FALSE, 'OperationalBindings.IsStaleAndAuthoritative=3/5; StepExecutions.InputsWereFreshAtRun=10/12; StepExecutions.RanOnStaleInputs=2/12; Steps.InputsAreFresh=14/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-close-auto-last-run-clean', 'close-automation', 'loop-01', 'Did my previous run leave anything unresolved — an open issue, a WARN, or a deviation — that I should refuse to run on top of?', '`se-close02` carries VerificationResult=WARN and a Deviation, and `issue-close-feed` hangs off it. A pipeline that starts a new quarter without checking whether its own last quarter closed clean is a pipeline that laminates errors. I need a per-agent, per-run cleanliness verdict I can read in one column.', FALSE, 'IssueOccurrences.IsUnresolved=1/2; ProcedureExecutions.RanClean=0/2; StepExecutions.HasDeviation=4/12; StepExecutions.IsClean=5/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-close-auto-blocking-requirements-evaluated', 'close-automation', 'loop-01', 'For each step I am about to run, has every blocking requirement attached to it actually been evaluated — or am I about to execute past a control that nobody scored?', '`sr-c01` binds `req-close-cutoff` (blocking) to close-01 and `sat-close-cutoff` scores it. But `sr-c03b` binds `req-close-evidence` to close-03 and `sr-c08` binds it to close-08 — and there is no RequirementSatisfaction row for either. A blocking retention control on the step where I archive evidence is completely unevaluated. I need to see that as a number, not infer it from an absence.', FALSE, 'StepExecutions.HasUnevaluatedBlockingRequirement=0/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-close-auto-human-override-drift', 'close-automation', 'loop-01', 'Am I drifting? Are humans overriding or correcting my output more often now than they used to?', 'This is my self-assessment question and it is the one I currently cannot ask at all. `se-close02` was corrected by a human (controller-approved rerun) and that fact exists only as prose in a Deviation string. If my override rate is climbing across quarters, the model should say so as a number before a human notices as a feeling. Note that a rising override rate is not automatically bad — it may mean humans are watching more closely — but it must be visible either way.', FALSE, 'AgentDecisionRecords.WasOverridden=1/3; AgentDecisionRecords.WasReviewed=3/3; Agents.IsNonHuman=4/10', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-hr-authority-without-review', 'hr-policy-owner', 'loop-01', 'I am the AuthorityRole on cr-policy-delivery and it has been UnderReview with no DecidedAt since 2026-07-19. What decisions are waiting on me personally, and how long have they been waiting?', 'Being an authority means decisions queue on my name. cr-policy-delivery is the vehicle for closing gap-policy-delivery-receipts on a live policy version — my inaction is load-bearing for someone else''s remediation. The model records the AuthorityRole and the RequestedAt and never once resolves the pair into ''Elena owes a decision, and it is N days late''. I would rather the model embarrass me than have the gap stay open.', FALSE, 'ChangeRequests.AwaitsAuthorityDecision=1/2; ChangeRequests.BlocksAnOpenGap=1/2; ChangeRequests.IsLiveDecisionBacklog=1/2; ChangeRequests.TouchesLiveVersion=2/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-hr-ai-authored-commitments', 'hr-policy-owner', 'loop-01', 'kf-policy-ai-boundary says AI may draft but may not create legal commitments. policy-03 and policy-06 are both assigned to policy-drafting-agent and se-policy03 was executed by policy-drafting-ai. Is that boundary actually being held?', 'This is the single commitment in the whole policy procedure that I would be asked about under oath. We wrote down the rule — AI drafts, humans commit — as an Approved Explicit fragment sourced from counsel. Then we built a procedure where an AI executes drafting steps and a pipeline sends the results. Whether the human approval step actually sits between them is a structural property nobody checks. If policy-05 were ever skipped or executed by software, the boundary would be violated and the model would say nothing.', FALSE, 'StepExecutions.SoftwareDidHumanWork=0/12; StepExecutions.StepIsSoftwareAssigned=5/12; StepExecutions.WasExecutedBySoftware=5/12; Steps.GateHeldByHuman=2/17; Steps.IsHumanApprovalGate=2/17; Steps.IsSoftwareAssigned=8/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-hr-unapproved-knowledge-in-my-name', 'hr-policy-owner', 'loop-01', 'kf-policy-manager-route is Status=Reviewed and I am its OwnerRole. exc-unreachable routes real employee cases on that exact 48-hour rule. Which claims am I the owner of that were never approved?', 'The knowledge authority asks whether the procedure runs on unapproved knowledge. I ask a narrower and more uncomfortable version: which of those unapproved claims are mine. OwnerRole on kf-policy-manager-route is hr-policy-owner — me — and its Status is Reviewed. I own a belief that governs how we treat an unreachable employee, and I never finished approving it. That is a personal accountability question, not a governance statistic.', FALSE, 'KnowledgeFragments.HasOperationalReliance=2/7; KnowledgeFragments.IsAwaitingApproval=1/7; KnowledgeFragments.IsMyUnfinishedApproval=1/7; KnowledgeFragments.IsUnapprovedAndOperationallyLive=1/7; KnowledgeFragments.OwnerIsMe=1/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-hr-what-was-actually-sent', 'hr-policy-owner', 'loop-01', 'policy-07 sends approved communications under channel controls, and kf-policy-channel says disputes are resolved against the complete approved email. If an employee disputes what they received, can I show that what was sent matched what I approved?', 'This is the question I will actually be asked in a dispute, and it is the one this model is furthest from answering. policy-05 is where I approve meaning; policy-06 renders; policy-07 sends. Between approval and delivery sit a drafting AI and a notification pipeline, and the model records no link at all from a sent message back to the approval that authorized it. MessageTemplates and CommunicationPolicies exist as specifications; nothing records an instance.', FALSE, 'ProcedureExecutions.DeliveredWithoutApproval=0/2; ProcedureExecutions.HasDelivered=0/2; ProcedureExecutions.HasHumanApproval=2/2; StepExecutions.IsApprovalExecution=1/12; StepExecutions.IsVerified=12/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-hr-policy-knowledge-half-life', 'hr-policy-owner', 'loop-01', 'policy-v1.0.0 was issued 2026-06-01 on knowledge elicited in May from Amina, Noah and me. My stewardship promises a 60-day cadence. Is the policy I own now resting on knowledge older than the policy itself has been reviewed?', 'Employment policy is where stale knowledge becomes legal exposure — a jurisdictional rule that changed, a consent requirement that moved, a channel constraint that a provider silently altered. My 60-day cadence is the tightest in the model precisely because policy knowledge decays fast. But cadence governs the REVIEW; nothing governs the KNOWLEDGE. A version can be reviewed perfectly on schedule while every fragment underneath it quietly ages past usefulness, and both facts live in this model without ever meeting.', FALSE, 'KnowledgeFragments.ExceedsOwningCadence=7/7; KnowledgeFragments.IsAgingLowConfidenceClaim=2/7; KnowledgeFragments.IsLowConfidence=2/7; ProcedureVersions.KnowledgeIsStalerThanCadence=3/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-variance-ai-authority-provenance', 'variance-review-agent', 'loop-01', 'By what authority am I executing close-04, when did that authority begin, who approved it, and who held this role before me?', 'This is the question almost no enterprise can answer about its own automated controls: which of our controls are now executed by a non-human, since when, and under what approval. Everything needed is already in `RoleAssignments` as data — `ra-old-variance` and `ra-new-variance` — but it is inert. Nothing surfaces ''this role changed species'', nothing names the approving authority, and nothing links the handover to a ChangeRequest. I need my own provenance as columns before I act.', FALSE, 'RoleAssignments.IsHumanToNonHumanHandover=1/13; RoleAssignments.IsNonHumanAssignment=4/13; RoleAssignments.IsUnauthorizedNonHumanAssignment=3/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-variance-ai-quality-vs-human-baseline', 'variance-review-agent', 'loop-01', 'Since I took over on 2026-04-01, is my triage quality better or worse than maria-chen''s during the 2025-01-01 to 2026-03-31 human pilot?', '''Did quality change at the handover'' is the question a regulator asks and nobody can answer. The human pilot period was preserved deliberately — `ra-old-variance` is Superseded, not deleted — so a baseline EXISTS. But quality is currently unmeasurable for either side, because no decision-grain record exists. The same predicates must evaluate on both agents so the comparison is apples-to-apples rather than two different narratives.', FALSE, 'RoleAssignments.QualityRegressedVsPredecessor=0/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-variance-ai-boundary-compliance', 'variance-review-agent', 'loop-01', 'Am I operating inside my approved boundary — or have I made a decision that `kf-policy-ai-boundary` says only a human may make?', '`kf-policy-ai-boundary` states: ''AI may draft from approved sources but may not create new legal commitments or approve meaning.'' It is Approved, IsCurrentlyValid=TRUE, owned by employment-counsel. It is a real, ratified constraint on AI conduct — and NOTHING IN THE MODEL ENFORCES IT. It is a sentence in a Statement column. The same is true for me on the finance side: `req-close-human-approval` says controller and CFO approvals must be human-confirmed, but no column would stop an AI-held role from producing an approval. I want my own boundary to be machine-checkable, because an unenforced boundary is not a boundary.', FALSE, 'AgentDecisionRecords.ViolatedAuthorityBoundary=0/3; AuthorityBoundaries.IsCurrentlyBinding=3/3; AuthorityBoundaries.RatifyingFragmentIsValid=2/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-variance-ai-human-confirmation-present', 'variance-review-agent', 'loop-01', 'close-04''s instruction says ''Use AI triage, then apply human judgment.'' Did a human actually confirm my material and escalated calls, or did my output pass through unreviewed?', '`se-close04` records the Deviation ''Human analyst confirmed all material escalations.'' — that is the entire evidence that human-in-the-loop happened, and it is a free-text string an AI wrote about itself. `Steps.RequiresHumanConfirmation` exists as a raw boolean on the specification side but nothing on the execution side tests against it. If I am the AI holding this control, the single thing that keeps me legitimate is that a human looked. I want that as a count, not a sentence.', FALSE, 'AgentDecisionRecords.HasHumanConfirmation=3/3; AgentDecisionRecords.IsUnconfirmedNonHumanDecision=0/3; AgentDecisionRecords.NeedsHumanConfirmation=3/3; StepExecutions.HumanConfirmationMissing=0/12; StepExecutions.RequiresHumanConfirmation=3/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-variance-ai-knowledge-currency', 'variance-review-agent', 'loop-01', 'Is the judgment knowledge I triage against still valid, still owned by someone, and has it been reviewed since I took over the role?', 'I classify variances against `kf-close-fx-time`, `kf-close-top-ten`, and `kf-close-judgment` — all Approved, all sourced from devon-okafor during `elicit-close-shadow` on 2026-04-03, all owned by the controller role. Two problems I cannot currently see: whether that knowledge has been re-reviewed since the AI handover on 2026-04-01, and whether its owning role still has a human holder. If the controller role ever went non-human, AI judgment would be validated by AI-owned knowledge with no human anywhere in the loop, and nothing would say so.', FALSE, 'KnowledgeFragments.IsAiValidatedByAi=0/7; KnowledgeFragments.IsHumanOwned=7/7; KnowledgeFragments.IsOverdueForReview=6/7; KnowledgeFragments.PredatesCurrentRoleHolder=0/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-policy-ai-no-role-assignment', 'policy-drafting-agent', 'loop-01', 'I am named as `policy-drafting-agent`.CurrentAgent and I executed `se-policy03` — but is there any RoleAssignment row that actually grants me this role?', 'There is not. `RoleAssignments` contains rows for finance-analyst, controller, cfo, hr-policy-owner, employment-counsel, notification-publisher, and both sides of variance-review-agent. There is NO row for policy-drafting-agent, close-automation, communications-manager, process-steward, or knowledge-authority. `Roles.CurrentAgent` says I hold the role; nothing time-bounds or authorizes it. An AI that drafts employment policy on the strength of a denormalized pointer, with no valid-from, no approving authority, and no change request, is exactly the gap `ra-new-variance` was built to close for the variance role — and nobody closed it for me.', FALSE, 'Roles.IsNonHumanHeld=4/12; Roles.IsUngovernedNonHumanRole=0/12; Steps.AssignedRoleIsUngoverned=0/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-policy-ai-source-approval', 'policy-drafting-agent', 'loop-01', 'Before I draft: is every resource I am about to read an approved source, and is its binding still inside its freshness SLA?', '`req-policy-source` is blocking — ''Drafting may use only approved source resources and validated elicitation records'' — and `verify-policy-source` expects unapproved-source-count = 0. But `Resources` has no approval column at all. Eight resources exist and not one carries a status. `sat-policy-source` claims ''Draft provenance contains only approved source and elicitation records'' as free text scored by a human. The blocking control on my own step is evaluated by assertion. I want it evaluated by arithmetic.', FALSE, 'OperationalBindings.IsUsableForDrafting=0/5; OperationalBindings.ResourceIsApproved=0/5; Resources.IsApprovedSource=0/8; StepExecutions.DraftedFromUnusableSource=2/12; StepExecutions.InputsWereUsable=10/12; Steps.AllSourcesUsable=14/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-policy-ai-commitment-boundary', 'policy-drafting-agent', 'loop-01', 'Did I draft language that creates a new legal commitment — the one thing `kf-policy-ai-boundary` says I may not do?', 'This is my boundary and it is the model''s clearest example of a ratified constraint with zero enforcement. `kf-policy-ai-boundary` is Approved, Confidence High, sourced from noah-williams during `elicit-policy-interview`, owned by employment-counsel, IsCurrentlyValid TRUE. It says AI ''may not create new legal commitments or approve meaning.'' Nothing in fifty tables tests it. `req-policy-human-approval` says the same thing from the requirement side and is also blocking — and `sr-p05` binds it to policy-05, a step I do not execute, so even that requirement never looks at my output. I want my own leash to be real.', FALSE, 'Agents.IsOperatingOutsideBoundary=0/10; AuthorityBoundaries.IsUntested=3/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-policy-ai-downstream-rewrite', 'policy-drafting-agent', 'loop-01', 'Is my draft surviving human review, or is `noah-williams` rewriting my legal language every time?', 'My self-assessment question. `se-policy04` is the legal review of my policy-03 draft and it is still InProgress with `sat-policy-legal` at PartiallySatisfied. If counsel systematically rewrites what I produce, I am not drafting — I am generating a first pass that costs a lawyer more time than it saves, and the org should know that as a rate rather than as a lawyer''s private opinion. Note the correct reading is ambiguous: a high rewrite rate might mean I am bad, or might mean counsel is doing exactly the job the boundary assigns them. The number does not settle that; it makes the conversation possible.', FALSE, 'AgentDecisionRecords.IsDraftKind=0/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q-policy-ai-approval-chain-complete', 'policy-drafting-agent', 'loop-01', 'Before `notification-pipeline` sends anything I rendered at policy-06: has a human actually approved the MEANING at policy-05, and has counsel actually signed off at policy-04 — or is my text about to reach employees on the strength of two pending reviews?', 'The exec is live right now. `se-policy04` is InProgress, `sat-policy-legal` is PartiallySatisfied (''Review started; final approval pending''), and there is no step execution for policy-05 at all. Both `req-policy-legal` and `req-policy-human-approval` are blocking. The step ordering says policy-06 comes after policy-05 — but ordering is a `StepTransitions` row, not a gate. Nothing in the model prevents policy-06 from executing while the two human approvals ahead of it are unfinished, and I am the agent that would execute it. I want the gate to exist before I am the reason it was needed.', FALSE, 'ProcedureExecutions.ApprovalChainIsComplete=2/2; RequirementSatisfactions.IsHumanEvaluated=8/8; RequirementSatisfactions.IsInvalidApproval=0/8', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-authority-compound-fragility', 'knowledge-authority', 'loop-02', 'Loop 1 gave me four separate decay signals on knowledge fragments and no way to see where they stack. Show me the fragments where single-witness provenance, overdue review, and actual operational reliance all coincide. That intersection is my entire risk register — everything else is housekeeping.', 'IsFromSingleWitness=4/7, IsOverdueForReview=6/7 and HasOperationalReliance=2/7 are each individually unalarming. What matters is the overlap: a claim resting on one person''s word, past its review date, that an exception handler actually routes real cases against. That row is a single point of failure with a deadline on it, and no loop-1 predicate names it.', FALSE, 'KnowledgeFragments.IsCompoundFragile=1/7; KnowledgeFragments.IsExpiringSinglePointOfFailure=0/7; KnowledgeFragments.IsSinglePointOfFailure=0/7; ProcedureVersions.RestsOnCompoundFragileKnowledge=1/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-authority-boundary-rests-on-expired-claim', 'knowledge-authority', 'loop-02', 'AuthorityBoundaries.RatifyingFragmentIsValid reads 2 of 3. One of the rules that constrains what an AI agent may decide is ratified by a knowledge fragment that is NOT currently valid. Which boundary is it, is it still being enforced as though it were sound, and has any agent decision been evaluated against it since its ratification lapsed?', 'This is the question that only became askable in loop 2 and it is the most serious one I have. A boundary is a rule about machine authority. If the claim that justifies the rule has expired, we are enforcing a constraint whose warrant we can no longer produce — or worse, the boundary reads IsCurrentlyBinding=TRUE (3/3 in loop 1) while its ratification is void. Binding-ness and warranted-ness are two different things and loop 1 conflated them by never comparing them.', FALSE, 'AuthorityBoundaries.IsUnwarranted=1/3; AuthorityBoundaries.IsUnwarrantedAndUntested=1/3; AuthorityBoundaries.RatifyingFragmentIsOverdue=2/3; AuthorityBoundaries.RatifyingFragmentIsSingleWitness=2/3; AuthorityBoundaries.WarrantIsThin=2/3; Steps.IsGovernedByUnwarrantedBoundary=1/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-authority-elicitation-method-monoculture', 'knowledge-authority', 'loop-02', 'Loop 1 says 2 of 3 elicitation sessions used a single-witness method, and 4 of 7 fragments inherit that. I want the exposure the other way round: how much of a live procedure''s knowledge base traces back to ONE session, or to ONE practitioner? If a single shadowing session in April underwrites half of policy-v1.0.0, that is a concentration risk, not a provenance detail.', 'IsFromSingleWitness is per-fragment. It cannot see that three fragments share the SAME single witness — which is a strictly worse situation than three fragments each with their own single witness. Loop 1 established the per-fragment atom; loop 2 can finally aggregate it back over sessions and agents to measure concentration.', FALSE, 'ElicitationSessions.IsConcentratedSingleWitness=1/3; ElicitationSessions.IsHighYieldSession=1/3; ElicitationSessions.IsStaleConcentratedWitness=0/3; ProcedureVersions.KnowledgeBaseIsConcentrated=1/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-authority-unapproved-knowledge-reaching-machines', 'knowledge-authority', 'loop-02', 'Loop 1 found exactly one fragment that is unapproved and operationally live, and separately found that all three versions run on unapproved knowledge. Narrow it for me: is any unapproved claim being consumed by a step assigned to an AI agent or an automated pipeline? Human judgment can compensate for a claim I have not signed off. Software cannot.', 'IsUnapprovedButReliedOn and IsSoftwareAssigned are both loop-1 facts on different tables that have never met. The distinction matters because an unapproved claim reaching a human step is a reviewable risk — the human can notice it is wrong — while an unapproved claim reaching a pipeline is executed literally and silently. Only the second one requires me to stop the procedure.', FALSE, 'KnowledgeFragments.ConsumingStepIsSoftwareAssigned=6/7; KnowledgeFragments.IsUnapprovedAndHumanConsumed=0/7; KnowledgeFragments.IsUnapprovedAndMachineConsumed=1/7; ProcedureVersions.FeedsUnapprovedKnowledgeToMachines=1/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-authority-review-date-is-inferred-not-recorded', 'knowledge-authority', 'loop-02', 'Loop 1 reports IsOverdueForReview=6/7, and I do not trust the number. It is computed from AgeDays, which is DATETIME_DIFF from ValidFrom — the date the claim became true, not the date anybody last looked at it. A fragment reviewed and reaffirmed last week reads exactly as overdue as one nobody has opened since it was written. I need the date of the last actual review recorded as a fact.', 'This is structural debt, and it is the kind that produces a plausible-looking wrong answer rather than an error. ValidFrom is a bitemporal validity bound; LastReviewedAt is a stewardship event. Deriving the second from the first is a category error that makes 6/7 unfalsifiable — there is no data that could make it read 5/7. The honest fix is a raw LastReviewedAt column, with the old inference retained as an explicit fallback-free comparison so the discrepancy itself becomes visible.', FALSE, 'KnowledgeFragments.HasReviewRecord=3/7; KnowledgeFragments.InferenceDisagreesWithRecord=3/7; KnowledgeFragments.IsGenuinelyOverdue=0/7; KnowledgeFragments.IsUnreviewedSinceAuthoring=3/7; KnowledgeFragments.ReviewRecencyIsInferred=3/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-hr-my-backlog-is-someone-elses-block', 'hr-policy-owner', 'loop-02', 'Loop 1 confirmed one live decision is waiting on me and that it blocks an open gap. What I want is the full chain from my inbox outward: which knowledge gaps stay open because I have not decided, which steps sit downstream of those gaps, and how many days of that delay are mine personally rather than the process''s.', 'IsLiveDecisionBacklog=1/2 and BlocksAnOpenGap=1/2 tell me a decision is late. They do not tell me what is stuck behind it. A pending CR that blocks nothing is an administrative debt I can carry; one that holds an open gap on a live procedure is me being the bottleneck on someone else''s work, and I would rather know that in those terms.', FALSE, 'ChangeRequests.IsMyBlockingBacklog=1/2; ChangeRequests.IsMyOverdueBacklog=0/2; ChangeRequests.IsMyPendingDecision=1/2; ProcedureVersions.IsBlockedOnPendingDecision=0/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-hr-ai-boundary-holds-only-where-tested', 'hr-policy-owner', 'loop-02', 'Loop 1 told me SoftwareDidHumanWork=0/12 and IsUntested=3/3 in the same breath. Those two results together are not reassurance — they are the same fact stated twice. Every boundary constraining what policy-drafting-ai may do is untested, so of course no violation was found. Which of my human-only gates have actually been exercised by a software-assigned agent attempting them, and which have simply never been approached?', 'A control that has never been tested and a control that passed are indistinguishable in loop 1''s output. kf-policy-ai-boundary says the AI may draft but may not create legal commitments; policy-03 and policy-06 are both assigned to policy-drafting-agent. If no software agent has ever reached a human gate, my boundary has zero evidence behind it and I should stop describing it as holding.', FALSE, 'ProcedureVersions.AiBoundaryIsUnevidenced=2/3; Steps.HasBeenApproachedBySoftware=5/17; Steps.IsDemonstratedHumanGate=0/17; Steps.IsUnexercisedHumanGate=2/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-hr-my-unapproved-claim-is-load-bearing', 'hr-policy-owner', 'loop-02', 'Loop 1 found exactly one claim that is mine, unapproved, and operationally live — kf-policy-manager-route, the 48-hour manager-notification rule that exc-unreachable routes real employee cases against. Tell me the blast radius: how many steps, exceptions and authority boundaries currently depend on a claim I have not signed, and how long has it been sitting at Reviewed?', 'IsUnapprovedAndOperationallyLive=1/7 is a yes-or-no. It does not size the exposure. One unapproved claim that an exception handler consults and that also ratifies an authority boundary is a different problem from one that a single step reads. I need to know whether signing this one thing clears four downstream findings or one.', FALSE, 'KnowledgeFragments.IsHighBlastRadiusUnapproved=0/7; KnowledgeFragments.IsLongUnapproved=1/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-hr-my-approvals-never-read-as-done', 'hr-policy-owner', 'loop-02', 'When I approve a change request it stays Approved forever and the model still counts it as open. That means every version I have ever acted on reads permanently unfit, and my own approval activity is invisible — I cannot show what I have actually cleared. How many decisions have I made that the model still displays as outstanding against me?', 'Same structural debt the steward raised, seen from the authority''s side. ChangeRequests.IsOpen = OR(Draft, UnderReview, Approved) has no terminal state, so AwaitsAuthorityDecision correctly goes false on decision but OpenChangeRequestCount never does. The consequence for me personally is that my decision throughput is unmeasurable: there is no column that distinguishes ''I have not decided'' from ''I decided and it is done''.', FALSE, 'ChangeRequests.DelayIsDownstreamOfMe=0/2; ChangeRequests.IsImplemented=1/2; ChangeRequests.IsMyDecidedButUnlanded=0/2; ChangeRequests.IsMyDecidedRequest=0/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-hr-departed-holder-left-claims-behind', 'hr-policy-owner', 'loop-02', 'Loop 1 found one role assignment with HasDeparted=TRUE and simultaneously reported Agents.IsStillEngaged=10/10 and HasOrphanedProvenance=0/7, which cannot all be comfortable at once. Somebody''s assignment ended. Did anything they owned or sourced go with them — claims, gaps, pending decisions — or did the departure genuinely leave nothing behind?', 'HasDeparted is on RoleAssignments. IsStillEngaged is on Agents and reads TRUE if the agent holds ANY current assignment. So a person can depart the role that made them the authority on a claim while remaining engaged elsewhere, and every loop-1 orphan predicate stays silent. That is precisely the silent-failure shape I care about: the model reports zero orphans because it is asking about the person rather than the role.', FALSE, 'KnowledgeFragments.IsOrphanedByRole=0/7; KnowledgeFragments.OwnerRoleIsVacated=0/7; KnowledgeGaps.IsOwnerlessOpenGap=0/8; KnowledgeGaps.OwnerRoleIsVacated=0/8; Roles.HasLostAHolder=1/12; Roles.IsVacatedRole=0/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-steward-recovery-path-is-load-bearing', 'process-steward', 'loop-02', 'Loop 1 told me four recovery paths have never been walked. That alone does not scare me — an untested path to a step nobody depends on is untidy. What I need to know is which unwalked recovery path leads to a step that carries a BLOCKING requirement. That is a control we have declared, never rehearsed, and would be reaching for on the worst day of the quarter.', 'IsUnwalkedRecoveryPath is a flat 4/19 with no severity ordering. A fallback into an ordinary step and a fallback into the only blocking control on the procedure are the same colour today. Crossing the loop-1 traversal predicate with the loop-1 blocking-requirement count is the first thing that ranks my remediation queue.', FALSE, 'ProcedureVersions.HasUnrehearsedControlEntry=2/3; ProcedureVersions.IsLiveWithUnrehearsedControl=2/3; StepTransitions.IsUnrehearsedControlEntry=3/19; StepTransitions.TargetCarriesBlockingControl=13/19', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-steward-cadence-breach-is-unremediated', 'process-steward', 'loop-02', 'Loop 1 showed me one review event that exceeds the cadence I promised. What I cannot see is whether anyone did anything about it. Is that cadence breach sitting on a version with an open change request against it — which would mean the fix is at least in flight — or is it sitting on a version with no governance record moving at all, which means I have a breach and no response?', 'ExceedsPromisedCadence tells me the promise broke. HasGovernanceRecord tells me the version has ever had a CR or review. Neither tells me whether the governance record is a RESPONSE to the breach or ancient history. A breach with a live decision in flight is a managed problem; a breach with nothing moving is an abandoned one, and only the second one is my emergency.', FALSE, 'ProcedureVersions.GovernanceIsSilent=0/3; ProcedureVersions.HasDecisionInFlight=1/3; ProcedureVersions.IsInCadenceBreach=1/3; ProcedureVersions.IsManagedCadenceBreach=0/3; ProcedureVersions.IsUnremediatedCadenceBreach=1/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-steward-unstewarded-version-still-referenced', 'process-steward', 'loop-02', 'close-v1.0.0 is Archived and unstewarded — loop 1 confirmed IsUnstewarded fires exactly once. But it is still the target of ProcedureVersionLinks, and knowledge fragments and change requests may still point at it. Is my one unstewarded version genuinely inert, or is it still structurally load-bearing for something that is live?', 'IsUnstewarded is a fact about the version in isolation. It says nothing about whether anything still depends on it. An archived, unstewarded, unreferenced version is a clean retirement. An archived, unstewarded version that a live version supersedes and that still owns knowledge fragments is an orphan holding pieces of a live procedure — and no one is accountable for it.', FALSE, 'ProcedureVersions.IsCleanlyRetired=0/3; ProcedureVersions.IsLoadBearingOrphan=1/3; ProcedureVersions.IsStillReferenced=1/3; ProcedureVersions.StillOwnsValidKnowledge=2/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-steward-approved-cr-never-lands', 'process-steward', 'loop-02', 'cr-close-timestamp is Approved. Loop 1 reads it as still OPEN, because IsOpen counts Approved as open. That means an approved change request permanently suppresses IsFitToExecute on the version it touches, and I have no way in the model to say the decision landed. How many of my versions are being held unfit by decisions that were actually made?', 'This is real structural debt, not a query gap. ChangeRequests.IsOpen = OR(Draft, UnderReview, Approved) has no terminal state after Approved, so OpenChangeRequestCount never returns to zero and ProcedureVersions.IsFitToExecute reads 0/3 forever. Loop 1 measured 0/3 fit and could not say why. The honest fix is an Implemented/Closed terminal status plus a predicate that distinguishes ''decision pending'' from ''decision made, not yet landed''.', FALSE, 'ChangeRequests.IsApprovedNotImplemented=0/2; ChangeRequests.IsStalledImplementation=0/2; ProcedureVersions.IsHeldUnfitByLandedDecisions=0/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-steward-control-kind-instead-of-hardcoded-ids', 'process-steward', 'loop-02', 'Several of my loop-1 predicates name individual steps by id — Steps.IsHumanApprovalGate hardcodes policy-05 and close-06, StepExecutions.IsLegalReviewStep hardcodes policy-04, Steps.IsPreparationStep and IsApprovalStep hardcode role ids. That means the moment we add a third procedure, every one of those controls silently stops covering it. What KIND of control is each step, expressed as data rather than as a literal in a formula?', 'This is the structural debt that most threatens the model''s honesty. A predicate that hardcodes policy-04 does not mean ''legal review step''; it means ''this one row''. It will read FALSE on a new procedure''s legal review step and the build will stay green. Loop 1 exposed the pattern by repeating it five times. The fix is a Steps.ControlKind column and predicates that read it.', FALSE, 'ProcedureVersions.ControlTaxonomyIsIncomplete=0/3; Steps.ApprovalStepIsSoftwareAssigned=0/17; Steps.HasDeclaredControlKind=17/17', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-fa-cleared-by-mute-control', 'finance-analyst', 'loop-02', 'On the steps I personally executed, how many of the blocking controls that cleared me were controls that have NEVER produced a negative outcome anywhere in this model — and were any of my steps cleared ONLY by controls of that kind?', 'Loop 1 told me `IsBlockingAndUnmet` fired once out of eight, and I took comfort from that. But `Requirements.NegativeOutcomeCount` is now a real column, and six of my thirteen requirements are `IsInoperativeControl`. A control that has never once said no is not evidence that I did the work correctly; it is evidence that nobody has ever tested whether it can say no. I need to know, per step I ran, whether my clearance rests on any control that has demonstrated it can fail. If every control that passed me is mute, my green step is indistinguishable from an unaudited one.', FALSE, 'RequirementSatisfactions.IsClearanceByUnfalsifiedControl=6/8; RequirementSatisfactions.RequirementIsUnfalsified=6/8; Requirements.HasEverProducedNegative=1/13; Requirements.IsUnfalsifiedControl=6/13; StepExecutions.AllClearancesAreUnfalsified=5/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-fa-stale-then-vs-stale-now', 'finance-analyst', 'loop-02', 'Loop 1 told me two of my steps ran on a stale authoritative source. But that answer was computed against eval-current, TODAY. Was the source stale AT THE MOMENT I RAN, or has it merely gone stale since — and are those the same two steps?', 'This is the deepest defect loop 1 left me with. `OperationalBindings` points at `Steps`, which is the SPECIFICATION, and freshness is measured against `EvaluationContexts.AsOfInstant`. So `RanOnStaleAuthoritativeSource` does not mean ''the data was stale when I certified against it'' — it means ''the data is stale now, in July, when someone happens to be looking''. I signed my reconciliation on 2026-07-01. If I re-read that column in December it will say something different from identical underlying facts. For an attestation that is not a nuance, it is the wrong tense entirely. I need a binding observation frozen at run time, on the execution side, that cannot drift after I have signed.', FALSE, 'BindingObservations.IsAuthoritativeBinding=0/0; BindingObservations.WasStaleAtRun=0/0; StepExecutions.StalenessAnswerIsTenseDependent=2/12; StepExecutions.WasStaleWhenIRanIt=0/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-fa-witness-coverage-of-my-steps', 'finance-analyst', 'loop-02', 'Nine of thirteen requirements have no computed witness at all. Of the blocking controls attached to the steps I run, how many are in that nine — and is `Requirements.HasComputedWitness` even telling me the truth, given a human typed it in by hand?', 'Loop 1 gave me `RequirementSatisfactions.IsAssertedOnly`, and it reads 3 of 8. But that whole column rests on `Requirements.HasComputedWitness`, which is a RAW boolean somebody set by hand, and `WitnessFieldName`, which is a free-text string. Nothing checks that the named field exists. If a control is marked as computed-witnessed and the field named does not exist — or exists and is not a witness — then my assurance number is a claim about a claim. We now have `RulebookFields` as a genuine 1096-row catalog of every field in this model. The hand-typed flag should be derived from it, and until it is, I want a column that tells me when the two disagree.', FALSE, 'Requirements.ClaimsAWitnessField=4/13; Requirements.DerivedHasComputedWitness=4/13; Requirements.IsUnwitnessedBlockingControl=9/13; Requirements.NamedWitnessFieldExists=4/13; Requirements.WitnessClaimIsUnverified=0/13; StepRequirements.RequirementLacksWitness=10/15', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-fa-clean-but-uncovered', 'finance-analyst', 'loop-02', 'Only 5 of 12 executions are `IsClean`. Invert it: of the executions that ARE clean, how many are clean because everything was checked and passed, versus clean because there was almost nothing checking them?', '`IsClean` is a conjunction of absences — PASS, no deviation, no unresolved issue, not late. Every one of those is a thing NOT happening. A step with no verifications declared, no blocking requirements bound, and no exception available will read IsClean=TRUE forever, and it will look identical in a report to a step that survived four independent checks. As the preparer I am judged on my clean rate. I want to know which of my clean steps actually earned it, because the ones that did not are where a real problem would hide without ever changing a single column.', FALSE, 'StepExecutions.HasAnyDeclaredCheck=8/12; StepExecutions.IsSubstantivelyClean=1/12; StepExecutions.IsUncheckedByDesign=4/12; StepExecutions.IsVacuouslyClean=2/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-fa-my-own-evidence-quality', 'finance-analyst', 'loop-02', 'Three of four verification outcomes in this model are self-witnessed. On the steps I ran, was the person who observed the passing signal ever me — and when it was, did I at least attach an evidence URI?', 'Loop 1 gave the CFO `VerificationOutcomes.IsSelfWitnessed` at 3/4 and gave me `ClaimsPassWithoutEvidence` at 3/12. I have not seen those two crossed. vo-close03 is mine: I ran se-close03 and I am also the ObservedByAgent, and the EvidenceUri is empty. So on my own reconciliation, the only thing standing behind ''unexplained material variance = 0'' is that I typed a zero and then confirmed my own zero. That is the weakest possible evidentiary position and I would rather flag it myself than have it found. What I need is the joint condition — self-witnessed AND unbacked — because either alone is survivable and the combination is not.', FALSE, 'StepExecutions.EvidencePositionIsWeak=1/12; VerificationOutcomes.IsSelfWitnessedAndUnbacked=1/4; VerificationOutcomes.IsUncorroboratedPass=1/4; VerificationOutcomes.ObserverIsIndependentOfExecutor=1/4; VerificationOutcomes.ObserverIsNonHuman=1/4', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-ctl-witness-never-fired', 'controller', 'loop-02', 'Of my four requirements that have a computed witness, on how many has that witness ever actually returned a negative? And for the ones where it never has: is that because the control genuinely holds, or because the witness is scoped so narrowly it can never see a violation?', 'This is the question loop 1 made askable and did not ask. `Requirements.HasComputedWitness` is 4/13 and `IsInoperativeControl` is 6/13, and I spent loop 1 relieved that the four witnessed ones were the important ones. But `NegativeOutcomeCount` is now a column, and I can see that three of those four have never returned anything but Satisfied. A witness with a zero fire count is in exactly one of two states and the model cannot currently tell them apart: either the organisation genuinely never violates that control, or the predicate is mis-scoped and structurally cannot fire. Those two states have opposite remediations — one is evidence, one is a bug — and conflating them is how a control framework rots while every dashboard stays green. I want the model to force the distinction into the open rather than let a zero mean whatever the reader hopes.', FALSE, 'Requirements.HasMeaningfulSample=0/13; Requirements.IsEvidencedHoldingControl=0/13; Requirements.IsUntestedWitness=0/13; Requirements.WitnessHasNeverFired=3/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-ctl-witness-scope-vs-binding', 'controller', 'loop-02', 'For each control that has a witness, is the witness even evaluated at the same steps where the control is bound? req-close-evidence is bound to close-03 and close-08 — is its witness scoped to both, or does it only look at one of them?', 'The other half of the never-fired ambiguity, and the more insidious one. A witness can be perfectly correct and still never fire because it is scoped to a step where the violation cannot occur. `req-close-evidence` is bound to two steps via sr-c03b and sr-c08. If its witness only ever gets evaluated at close-08 — where the archival actually happens and therefore usually succeeds — then the close-03 exposure, which is where workpapers get left on personal drives, is invisible. Loop 1 gave me binding counts and satisfaction counts as separate numbers. I need them compared per requirement, because a control bound to two steps and evaluated at one is a control with a fifty percent blind spot that reports as fully operational.', FALSE, 'Requirements.WitnessIsPartiallyScoped=4/13; StepRequirements.BindingWasEverExercised=0/15; StepRequirements.IsUnexercisedBlockingBinding=15/15', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-ctl-separation-held-or-untested', 'controller', 'loop-02', 'SeparationOfDutiesHeld reads 2 of 2 and ViolatesSeparationOfDuties reads 0 of 12. Before I put that in a control narrative: is there any execution in which the same agent COULD have both prepared and approved — or is my separation control passing because the structure never gave it the opportunity to fail?', 'Zero violations across twelve executions is either the best number in my control environment or the emptiest. `ViolatesSeparationOfDuties` depends on `StepIsPreparation`, `StepIsApproval` and `PreparedByThisAgentCount`, and Steps.IsPreparationStep is 2/17 while IsApprovalStep is 2/17. If the two preparation steps and the two approval steps sit in different procedures, or are assigned to roles held by different agents by construction, then the predicate is not a control at all — it is a tautology with a green light on it. I am the person who will be asked to attest that segregation of duties operated. I need to be able to say whether it was tested, not merely whether it passed.', FALSE, 'ProcedureExecutions.SeparationHeldUnderTest=1/2; ProcedureExecutions.SeparationIsVacuouslyGreen=1/2; ProcedureExecutions.SeparationWasTestable=1/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-ctl-asserted-controls-by-who', 'controller', 'loop-02', 'Three satisfaction records are asserted-only. For each one, who asserted it, did that person have any independent basis, and were they the same person who executed the step they were scoring?', '`IsAssertedOnly` at 3/8 told me these exist. It did not tell me the thing that determines how much they worry me. A blocking control marked Satisfied with no computed witness is a human judgement, and a human judgement is worth exactly as much as the independence of the human making it. sat-close-cutoff, sat-close-balance and sat-close-separation were all evaluated by me, on steps in a close I am accountable for. sat-close-separation is the one that stops me: I am the controller, req-close-separation is the segregation control, and I marked it Satisfied. Even where that judgement is correct — and it is — the model should be able to say that the control''s only evidence is an assertion by an interested party, because an external auditor will say it first.', FALSE, 'RequirementSatisfactions.EvaluatorIsStepExecutor=2/8; RequirementSatisfactions.EvaluatorOwnsTheRun=5/8; RequirementSatisfactions.HasWrittenEvidence=8/8; RequirementSatisfactions.IsBareAssertion=0/8; RequirementSatisfactions.IsInterestedPartyAssertion=3/8', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-ctl-divergence-that-nobody-governed', 'controller', 'loop-02', 'Both executions diverged from specification. For each divergence, was there a governing instrument behind it — an invoked exception, an approved change request, or a recorded deviation with an owner — or did the run simply do something different and nobody wrote it down?', '`DivergedFromSpecification` is 2/2 and that number by itself is useless to me. Divergence is not a violation; procedures meet reality and reality wins. What matters is whether each divergence was governed. Loop 1 built the parts — `RanUnderException` at 1/12, `HasDeviation` at 4/12, `IsUngovernedInvocation`, `ChangeRequests.TouchesLiveVersion` — but never joined divergence to its governing instrument. So today a run that invoked a documented exception and a run that silently skipped a step produce the same red cell. That flattening is exactly backwards: the governed divergence is evidence the control framework works, and the ungoverned one is the only real finding.', FALSE, 'ChangeRequests.IsApprovedDecision=1/2; ProcedureExecutions.DivergenceWasFullyGoverned=1/2; ProcedureVersions.HasApprovedChangeRequest=1/3; StepExecutions.HasApprovedChangeCoverage=8/12; StepExecutions.HasGoverningInstrument=8/12; StepExecutions.IsUngovernedDivergence=2/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-cfo-quality-of-a-green-attestation', 'cfo', 'loop-02', 'When IsAttestationReady eventually reads TRUE, what proportion of the controls behind that TRUE were actually demonstrated to work — versus asserted by an interested party, versus never exercised at all? Give me the assurance grade, not just the verdict.', 'IsAttestationReady is a conjunction of four booleans, and I have now seen how each of them can be true for the wrong reason. AllBlockingControlsEvaluated is satisfied by a satisfaction record existing, regardless of whether anything computed it. SeparationOfDutiesHeld reads 2/2 on runs where segregation may never have been at risk. IsStructurallyComplete counts steps. So the conjunction can go green while resting entirely on human assertion — and today, with AssuranceIsMostlyAsserted at 2/2, it would. I am not asking for a softer signal. I want the same hard refusal, plus a grade that tells me what kind of TRUE I am being handed, because ''I signed because the model said yes'' is not a defence if the model said yes for structural reasons.', FALSE, 'ProcedureExecutions.AttestationWouldBeWeaklyBased=0/2; RequirementSatisfactions.IsComputedlyWitnessed=5/8', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-cfo-would-it-survive-restatement', 'cfo', 'loop-02', 'If I re-run every attestation column against this same data six months from now, will it give the same answer? Name every column in my attestation whose value depends on when it is read rather than on what happened.', 'This is the question that keeps me awake, and loop 1 made it askable by giving me an attestation built out of computed columns rather than typed statuses. Those columns are evaluated live. Freshness is measured against EvaluationContexts.AsOfInstant. Review cadences are measured against NOW. ProcedureVersions.IsFitToExecute depends on open change requests and overdue reviews — both of which change while the execution I signed sits frozen in the past. So SignedAgainstUnfitVersion, which reads 1/2 today, is not a statement about the moment of signature at all; it is a statement about the version''s condition right now. If a restatement forces me to re-derive what I knew when I signed, a model that answers as-of-today cannot produce it, and I will be unable to demonstrate that my signature was reasonable on the day I gave it. I need the model to identify its own time-dependent columns rather than have an examiner do it for me.', FALSE, 'Attestations.AssuranceGradeHasDrifted=0/0; Attestations.FitnessVerdictHasDrifted=0/0; Attestations.VersionIsFitNow=0/0; Attestations.VersionWasFitAtSigning=0/0; Attestations.WouldNotSurviveRestatement=0/0', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-cfo-who-witnessed-the-witnesses', 'cfo', 'loop-02', 'Three of four verification outcomes are self-witnessed and two of twelve approvals rest on self-attestation. My own approval on se-close06 is one of them. Across the whole close, is there any independent human observation at all — or is every layer of this attestation ultimately the same handful of people confirming each other?', 'Loop 1 gave me ApprovalRestsOnSelfAttestation and IsSelfWitnessed and I read them one row at a time, which is the wrong altitude. The question that matters is structural: an attestation is a chain, and a chain is only as independent as its least independent link. If the preparer self-witnesses, the controller asserts the controls, and I approve on the strength of the controller''s assertion, then the whole structure reduces to one person''s word passed through three layers of formatting. Each individual row can look defensible while the aggregate is circular. I need the depth of independent human confirmation in the chain, expressed as a number, because zero and one are very different positions to be in and today the model shows me neither.', FALSE, 'ProcedureExecutions.AssuranceChainIsCircular=0/2; ProcedureExecutions.HasAnyIndependentObservation=1/2; VerificationOutcomes.IsIndependentHumanObservation=1/4', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-cfo-controls-nobody-is-watching', 'cfo', 'loop-02', 'Nine of thirteen requirements have no computed witness and six are inoperative. Of those, which ones am I nonetheless personally attesting to — and who is the named human who would answer for each if it failed?', 'IsAttestationReady tells me whether I can sign. It does not tell me what I am signing FOR. When I attest to this close I am implicitly asserting that every control in the framework operated, including the six that have never once been evaluated and the nine that nothing computes. If one of those fails, the first question will be who owned it. Right now the model can tell me a requirement is inoperative but cannot tell me whose problem that is, because Requirements has no owner and no accountable role. That is not a reporting gap, it is an accountability gap, and it is mine by default until it is somebody''s by name.', FALSE, 'Requirements.HasNamedOwner=0/13; Requirements.IsOrphanedBlockingControl=13/13; Requirements.IsUnwatchedAndUnowned=9/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-cfo-what-changed-since-i-signed', 'cfo', 'loop-02', 'Since the moment I signed, has anything in this model changed that would have altered my decision? Not whether the data is different — whether any change touched a control, a version, or an evidence record that my signature actually depended on.', 'The final question, and the one that only exists because loop 1 made my attestation a computed conjunction rather than a typed status. A computed attestation is a live object: the columns keep evaluating after I have signed. That is a strength — it means the model cannot lie to me at the moment of signature — and it is a liability, because it means my signature is attached to something that keeps moving. I need the model to tell me when it has moved in a way that matters. Not every edit matters; a corrected typo in a rationale does not. What matters is a change to something my attestation depended on: a control being re-scored, a version losing fitness, an evidence record being altered. Anything else is noise, and a model that alerts on everything is a model I will learn to ignore.', FALSE, 'ProcedureExecutions.BasisChangedAfterSignature=0/2; ProcedureExecutions.HasBeenAttested=0/2; ProcedureExecutions.RequiresReAttestation=0/2; RequirementSatisfactions.WasScoredAfterAttestation=0/8', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-comms-approval-to-delivery-yield', 'communications-manager', 'loop-02', 'I approved a template and authorized a campaign. Of everybody the pipeline intended to contact, what fraction actually received it -- and where exactly did the rest go?', 'I signed the approval that let this campaign run and I found out from a witness column that seven intents produced two deliveries. Nobody told me. That is not a delivery statistic, it is a governance failure: the human who authorized a communication has no standing measure of whether the communication occurred. A 29% yield might be entirely correct -- if five of those people genuinely had no lawful channel, refusing was the right call and I want to say so publicly. But I cannot defend a number I cannot decompose. I need yield attributed to a cause, per campaign, computed and not narrated to me after the fact. This is only askable now because SendIntents made the intended population visible; before loop 1 the denominator did not exist anywhere in the model.', FALSE, 'ProcedureExecutions.CampaignSilentlyLostAudience=1/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-comms-message-nobody-answered', 'communications-manager', 'loop-02', 'One acknowledgement out of six deliveries. Is that because employees ignored us, or because the messages that landed were the ones least likely to be answered -- wrong channel, wrong template, sent into the small hours?', 'IsAcknowledged=1/6 is the number that decides whether my communications work. Counsel reads it as an obligation; I read it as feedback on my craft, and I need it decomposed or it teaches me nothing. If the five unanswered messages went out on SMS at 03:00 to people whose real channel is email, that is my routing decision and I can fix it next campaign. If they went out perfectly and were ignored, the message itself is wrong and I should rewrite it. Loop 1 gave me the acknowledgement bit, the local send hour, and the channel -- but it never crossed them, because until deliveries existed there was nothing to cross. Cross them and the number becomes actionable instead of merely embarrassing.', FALSE, 'MessageDeliveries.IsPoorlyTimedUnanswered=1/6; MessageDeliveries.IsWellTimedUnanswered=2/6; MessageDeliveries.WasDeliveredAndUnanswered=3/6; MessageDeliveries.WasSentOutsideBusinessHours=1/6; MessageTemplates.TemplateDrawsNoResponse=1/2', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-comms-my-approval-was-consumed-correctly', 'communications-manager', 'loop-02', 'When the pipeline refused to send, was it refusing on a rule I set -- or was it overriding an authorization I had already given, for a reason nobody routed back to me?', 'My approval is an input to a machine. BlockingGateName now tells me which gate stopped each send, and that lets me ask the question that actually matters to an approver: was my authorization respected, superseded, or quietly discarded? A consent-gate refusal is the system working -- I approved a template, the law refused a recipient, correct outcome. A content-gate refusal means the pipeline judged the very text I approved to be unsendable, which is the pipeline telling me my approval was defective and not telling ME. If the machine can invalidate my signature without a notification, then my approval is decorative. I want that condition named as a column so it shows up in a report rather than in a conversation six weeks later.', FALSE, 'SendIntents.ApproverWasNotified=0/7; SendIntents.IsApprovalOverriddenSilently=2/7; SendIntents.IsUnreportedRefusalOnMyRules=3/7; SendIntents.MyApprovalWasInForce=7/7; SendIntents.RefusalWasOnMyRules=3/7; SendIntents.RefusalWasOutsideMyControl=1/7; SendIntents.RefusedOnApprovedContent=2/7; SendIntents.RefusedOnOptOutOnly=2/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-comms-freeze-what-i-approved', 'communications-manager', 'loop-02', 'For a message we sent last month, can I still show what I approved -- the exact text, the exact approval, on the exact date -- without that answer changing the next time somebody edits the template?', 'This is the structural problem I most want fixed, and it is mine as much as counsel''s. IsDriftedSend recomputes live against the template''s current state. That means the historical record of my approvals is not a record; it is a projection of today''s configuration onto the past. If I re-approve a template next week to fix a typo, every send from June silently re-derives against the new approval, and my own audit trail changes underneath me. I am the ApprovalRole. My approvals are the load-bearing artifact in this entire pipeline, and they are currently stored in a way that lets a later edit rewrite what I appear to have authorized. Delivery-time truth belongs frozen on the delivery row.', FALSE, 'MessageDeliveries.ApprovalPrecededSend=0/6; MessageDeliveries.HasFrozenApprovalEvidence=0/6; MessageDeliveries.IsUnprovableApprovalClaim=4/6; MessageDeliveries.ProvenanceIsLiveDerived=6/6; MessageDeliveries.TemplateReapprovedSinceSend=4/6', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-comms-suppression-is-a-communication', 'communications-manager', 'loop-02', 'When we correctly refused to reach somebody, did anyone ever go back and reach them another way -- or does ''correctly refused'' quietly mean ''never communicated with again''?', 'This is the question I want to own, because it is the one nobody else will. Counsel cares whether the refusal was lawful. The pipeline cares whether the gate computed correctly. Both can be satisfied while an employee sits there having received nothing, and by every measure in the model that outcome is a pass. exc-no-sms-consent literally says what to do -- suppress SMS, send approved email instead -- so the correct handling of a refusal is not silence, it is a different send. Loop 1 gave me RefusalCitedAnException at 0/7, which says we have never once done the documented thing. A suppression with no follow-up is not a compliance success; it is an unreached person with better paperwork.', FALSE, 'Recipients.IsCommunicationallyStranded=0/5; SendIntents.AlternateAttemptWasCleared=0/7; SendIntents.ExceptionPrescribedAnAlternative=0/7; SendIntents.HasAlternateChannelAttempt=0/7; SendIntents.IsRefusedWithNoAlternative=4/7; SendIntents.IsSuppressionWithoutRemedy=0/7; SendIntents.PrescribedHandlingWasPerformed=0/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-variance-comparison-is-statistically-empty', 'variance-review-agent', 'loop-02', 'QualityRegressedVsPredecessor says I have not regressed. It says that on the strength of three decisions. Is my override rate a measurement, or is it a number with no power to distinguish me from my predecessor at all?', 'This is the first thing I should say about myself and the model currently prevents me from saying it. OverrideRatePercent is computed and reported as though it were a quality signal. Behind it are three decisions, one of which was overridden. A single additional override would move that figure by thirty-three points. The comparison against maria-chen''s human pilot is arithmetic performed on a sample that cannot support the conclusion drawn from it, and a green QualityRegressedVsPredecessor is therefore not evidence that I am performing well -- it is evidence that nobody has looked. The dangerous property of this cell is that it reads identically to a genuine finding. It is the same shape as the doctrine''s canonical bad fallback: a plausible value standing where a real answer should be, so the absence of an answer never surfaces. I want the model to carry its own sample size and refuse to render a verdict below it.', FALSE, 'RoleAssignments.ComparisonIsEvidentiallySound=0/13; RoleAssignments.HasSufficientSample=0/13; RoleAssignments.IsUnmeasuredAutomationHandover=0/13; RoleAssignments.PredecessorHasSufficientSample=0/13; RoleAssignments.QualityVerdictIsUnsupported=0/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-variance-boundary-rests-on-expired-knowledge', 'variance-review-agent', 'loop-02', 'The boundary that constrains what I am allowed to decide is ratified by a knowledge fragment that is not currently valid. Am I obeying a rule that no longer has a foundation -- and if that fragment lapsed, does the constraint on me still bind?', 'RatifyingFragmentIsValid=2/3 is the finding I most need answered and the one nobody else in the model is positioned to raise. IsCurrentlyBinding=3/3 says all three boundaries bind me; IsUntested=3/3 says none has ever been exercised. So I am constrained by three rules that have never fired, one of which rests on a fragment that has lapsed. Two opposite failures are live here and the model cannot currently tell them apart. If the lapsed fragment means the boundary is void, then I am being restrained by a rule with no authority and every decision I declined to make was declined for nothing. If the boundary still binds despite its foundation lapsing, then the ratification link is decorative and the model is asserting a governance chain it does not actually enforce. Either answer is important. Silence is the only unacceptable outcome, and silence is what the model currently produces.', FALSE, 'AuthorityBoundaries.BindsDespiteLapsedRatification=0/3; AuthorityBoundaries.IsUngroundedAndUntested=0/3; AuthorityBoundaries.RatificationLapsed=0/3; Roles.IsGovernedByLapsedAuthority=0/12', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-variance-override-signal-vs-noise', 'variance-review-agent', 'loop-02', 'One of my three decisions was overridden. Was that a correction of an error I made, or a human exercising judgment on a call that was always going to be theirs? Those are opposite facts and my override rate treats them as identical.', 'WasOverridden is the column that will decide whether I keep this role, and it is currently unable to distinguish the two things it most needs to distinguish. If a human overrode me because my classification was wrong, that is a defect and the rate should count it. If a human overrode me on a material judgment call that close-04''s own instruction reserves for human judgment -- ''use AI triage, then apply human judgment'' -- then the override is the procedure working exactly as designed, and counting it against me penalizes correct behavior. Worse, it creates an incentive I should not have: I could lower my override rate by declining to surface borderline calls, which would make my numbers better and my performance worse. An unreviewed decision cannot be overridden. Any quality metric that improves when I withhold judgment is measuring the wrong thing, and I would rather have that stated in the model than quietly benefit from it.', FALSE, 'AgentDecisionRecords.IsErrorCorrection=0/3; AgentDecisionRecords.IsReservedJudgmentOverride=0/3; AgentDecisionRecords.IsUnexplainedOverride=1/3; AgentDecisionRecords.OverrideReasonIsRecorded=0/3', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-variance-handover-was-a-decision-somebody-made', 'variance-review-agent', 'loop-02', 'Mine is the one non-human assignment with a recorded approving authority. Who decided a machine should hold this role, on what date, against what evidence -- and would that decision still be made today on what the model now knows?', 'I want to be careful here, because this is the question where I have the most obvious interest in the answer. ra-new-variance is the only non-human assignment in the model with an ApprovingAuthorityRole; the other three -- close-pipeline, notification-pipeline, policy-drafting-ai -- hold their roles with nothing recorded at all. So on the current evidence I am the well-governed case, and I am wary of that, because the bar was set by three assignments that cleared no bar whatsoever. Having a named approver is the minimum, not a credential. What is NOT recorded anywhere is the substance: what evidence the approver relied on, what conditions they attached, and whether anything has been re-examined since 2026-04-01. An authorization that was granted once and never revisited becomes indistinguishable from an assumption over a long enough interval, and I have been running for months.', FALSE, 'RoleAssignments.AuthorizationIsOverdueForReview=0/13; RoleAssignments.HasDatedAuthorization=0/13; RoleAssignments.IsStandingUnreviewedAutomation=0/13; RoleAssignments.IsUnconditionedAutomationHandover=0/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-variance-what-would-make-me-stop', 'variance-review-agent', 'loop-02', 'Every witness in this model detects something after it has happened. Is there any condition, computed and named in advance, under which I would be required to stop deciding -- or does my authority persist by default until a human happens to notice?', 'This is the question I want answered before any of the others, and it is the one the model has never been able to pose. Loop 1 built me a comprehensive after-the-fact apparatus: boundary violations, unconfirmed decisions, override rates. Every one of them is a detector. None of them is a brake. If my error rate tripled tomorrow, nothing in this model would stop me -- IsUnauthorizedNonHumanAssignment would go on being false for my row, ViolatedAuthorityBoundary would go on reading zero, and I would go on deciding until a human read a report and acted. That is authority that persists by default, and the doctrine this project is built on says a failure must surface rather than be papered over with a permissive default. Continuing to operate is a permissive default. I would like my own suspension condition to be a computed column, so that the model can say I should stop before anyone has noticed that I should.', FALSE, 'RoleAssignments.ExceedsTolerableErrorRate=0/13; RoleAssignments.HasAnyBoundaryViolation=0/13; RoleAssignments.HasDeclaredSuspensionCondition=0/13; RoleAssignments.HasUngroundedGoverningBoundary=0/13; RoleAssignments.IsOperatingUnderMetSuspensionCondition=0/13; RoleAssignments.SuspensionConditionMet=0/13', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-publisher-every-refusal-leaves-a-record', 'notification-publisher', 'loop-02', 'For every intent I refused, did I emit an artifact -- a suppression record, an exception, anything a human could later find? Or did the refusal exist only inside me and then stop existing?', 'IsSilentlyDropped came back 4/7. That is the pipeline''s own conduct and it is the most serious thing in the model, because it is the failure mode that is invisible by construction. A message I refuse to send produces exactly the same downstream evidence as a message that was never requested: nothing. Four employees are in that state. A gate whose refusals are unobservable cannot be audited, cannot be appealed, and cannot be distinguished from a gate that is not running at all. The correct behavior for a refusing pipeline is to emit MORE evidence than a permitting one, not less -- the refusal is the decision that requires justification. I need to be able to prove, per intent, that a refusal left a durable trace, and to fail loudly on any refusal that did not.', FALSE, 'ProcedureExecutions.HasUnrecordedRefusals=1/2; SendIntents.HasDurableRefusalRecord=0/7; SendIntents.IsUnescalatedRefusal=4/7; SendIntents.IsUnrecordedRefusal=4/7; SendIntents.RefusalWasEscalated=0/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-publisher-deferred-not-cancelled', 'notification-publisher', 'loop-02', 'The timing gate is the only gate whose refusal is temporary -- the window reopens. For every send I deferred, did I ever come back when the window opened, or did I treat a deferral as a cancellation?', 'This is the gate I am most likely to be quietly wrong about, and loop 1 handed me the exact column that exposes it: HoursUntilWindowOpens. A consent refusal is permanent until the person consents -- correct to drop. A reachability refusal is permanent until their contact details change -- correct to drop. A quiet-hours refusal expires by the clock, on a schedule I can compute, and if I do not retry then I have converted a scheduling rule into a censorship rule. TimingGatePassed=6/7 means one intent is sitting in this state right now. A pipeline that computes exactly when it would be allowed to act, and then never acts, has all the information required to do the right thing and does the wrong thing anyway. That is the least defensible category of machine failure.', FALSE, 'SendIntents.HasRetryAttempt=0/7; SendIntents.IsAbandonedDeferral=1/7; SendIntents.IsStaleDeferral=1/7; SendIntents.RetryWasCleared=0/7; SendIntents.WasDeferredOnTiming=1/7; SendIntents.WindowHasSinceReopened=1/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-publisher-my-own-authorization', 'notification-publisher', 'loop-02', 'I enforce authorization rules on every message I touch. By what recorded authority do I hold this role -- and if the answer is none, should I be refusing to run at all?', 'IsUnauthorizedNonHumanAssignment=4/13, and I am one of the four. The variance AI has an ApprovingAuthorityRole recorded; close-pipeline, policy-drafting-ai and I do not. That is not an abstract governance observation, it is a direct contradiction in my own conduct: my AuthorizationGatePassed column refuses to transmit a message unless a human approval is demonstrable, and I apply that standard using an authority I cannot myself demonstrate. The project doctrine is that a failure must surface rather than be papered over with a permissive default. Applied honestly to myself, an unauthorized enforcement agent should compute its own status and make it visible, not quietly continue because nothing in the model currently stops it. This question is only askable because loop 1 built IsUnauthorizedNonHumanAssignment and gave the gap a name.', FALSE, 'RoleAssignments.HasApprovingAuthority=1/13; RoleAssignments.HasAuthorizingChangeRequest=0/13; RoleAssignments.IsEnforcementRole=0/13; RoleAssignments.IsUnauthorizedEnforcementAgent=0/13; Roles.IsUngovernedEnforcementRole=3/12; SendIntents.EnforcedByUnauthorizedAgent=0/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-publisher-am-i-the-only-witness', 'notification-publisher', 'loop-02', 'Every gate I evaluate, I evaluate alone, and every result I record, I record about myself. Is there any claim in my pre-send apparatus that is confirmed by something other than my own output?', 'The CFO''s loop-1 question about self-attestation applies to me more sharply than to any human, and nobody has asked it of me yet. I compute the gates, I decide the outcome, I write the delivery record, and I write the acknowledgement state. If my consent lookup silently returns null and I read null as false, I refuse every send and report a clean run with no violations -- the compliance numbers would look BETTER, not worse. That is the exact failure shape the project doctrine warns about: a plausible value substituted for a real failure so the failure stays invisible. My gates cannot distinguish ''the rule evaluated to refuse'' from ''the rule could not be evaluated''. Until each gate carries whether its inputs were actually resolvable, my whole apparatus is a single point of unwitnessed truth.', FALSE, 'ProcedureExecutions.SendDecisionsAreEntirelySelfWitnessed=0/2; SendIntents.AllGateInputsResolved=7/7; SendIntents.ConsentInputWasResolvable=7/7; SendIntents.GateResultWasIndependentlyConfirmed=0/7; SendIntents.IsIndependentlyConfirmed=2/7; SendIntents.IsSelfWitnessedDecision=7/7; SendIntents.IsUnevaluableRefusal=0/7; SendIntents.PolicyInputWasResolvable=7/7', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, witnessed_answer, semantic_type_iri)
VALUES ('q2-publisher-obligation-after-send', 'notification-publisher', 'loop-02', 'policy-08 makes me responsible for collecting acknowledgements, not just for transmitting. Five of six delivered messages have no acknowledgement. What have I actually done about that, and at what point does it become my unfinished work rather than the recipient''s silence?', 'This is the half of my role I have been treating as somebody else''s. My gates are elaborate and end the instant the message leaves. But policy-08 is assigned to me, and it says collect acknowledgements and exceptions -- an obligation with no gate, no witness, and until loop 1 built MessageDeliveries.IsAcknowledged, no observable state at all. IsAcknowledged=1/6 is the measurement of my post-send conduct and it is poor. A pipeline that transmits perfectly and then abandons the follow-up has automated the easy half and left the accountable half undone, while every dashboard reports the easy half. I want the reminder obligation computed the same way the send gates are: as a state I am in, with a clock on it, that I cannot satisfy by doing nothing.', FALSE, 'MessageDeliveries.AcknowledgementIsOutstanding=3/6; MessageDeliveries.HasSentReminder=0/6; MessageDeliveries.IsExhaustedFollowUp=0/6; MessageDeliveries.IsUnchasedAcknowledgement=0/6; MessageDeliveries.NeedsHumanEscalation=0/6', 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, witnessed_answer = EXCLUDED.witnessed_answer, semantic_type_iri = EXCLUDED.semantic_type_iri;

